232→/**
233→ * Creates an authenticated test user and returns auth headers.
234→ */
235→export async function createTestUser(
236→  baseUrl: string,
237→  suffix: string,
238→): Promise<TestUser> {
239→  const email = `orch-${Date.now()}-${suffix}@test.local`;
240→  const response = await fetch(`${baseUrl}/api/auth/sign-up/email`, {
241→    method: "POST",
242→    headers: { "Content-Type": "application/json" },
243→    body: JSON.stringify({
244→      name: "Test User",
245→      email,
246→      password: "test-password-123",
247→    }),
248→    redirect: "manual",
249→  });
250→
251→  if (!response.ok) {
252→    const body = await response.text();
253→    throw new Error(`Failed to create test user (${response.status}): ${body}`);
254→  }
255→
256→  const setCookie = response.headers.getSetCookie();
257→  if (!setCookie || setCookie.length === 0) {
258→    throw new Error("Sign-up did not return session cookies");
259→  }
260→
261→  const cookieHeader = setCookie.map((c) => c.split(";")[0]).join("; ");
262→  return { headers: { Cookie: cookieHeader } };
263→}
