116→/**
117→ * Validate that a task exists, is in an assignable status, belongs to the
118→ * given workspace, and has no active agent session already working on it.
119→ */
120→export async function validateAssignment(
121→  surreal: Surreal,
122→  workspaceId: string,
123→  taskId: string,
124→): Promise<AssignmentResult> {
125→  // 1. Input validation
126→  if (!taskId) {
127→    return missingTaskId();
128→  }
129→
130→  const taskRecord = new RecordId("task", taskId);
131→
132→  // 2. Task existence
133→  const task = await fetchTask(surreal, taskRecord);
134→  if (!task) {
135→    return taskNotFound(taskId);
136→  }
137→
138→  // 3. Workspace membership
139→  const taskWorkspaceId = task.workspace.id as string;
140→  if (taskWorkspaceId !== workspaceId) {
141→    return workspaceMismatch(taskId);
142→  }
143→
144→  // 4. Status eligibility
145→  if (!isAssignableStatus(task.status)) {
146→    return taskNotAssignable(taskId, task.status);
147→  }
148→
149→  // 5. One-agent-per-task
150→  const alreadyActive = await hasActiveSession(surreal, taskRecord);
151→  if (alreadyActive) {
152→    return agentAlreadyActive(taskId);
153→  }
154→
155→  // All checks passed
156→  return {
157→    ok: true,
158→    validation: {
159→      taskRecord,
160→      workspaceRecord: task.workspace,
161→      taskStatus: task.status,
162→      title: task.title,
163→    },
164→  };
165→}
