  1→/**
  2→ * Workspace Repository Path: Assignment Guard and Lifecycle
  3→ *
  4→ * Traces: US-1 (set repo_path during creation), US-2 (prompt before assignment),
  5→ *         US-3 (update repo_path)
  6→ *
  7→ * Validates that the orchestrator requires a valid repo_path on the workspace
  8→ * before allowing task assignment, and that repo_path can be set during
  9→ * workspace creation or updated later.
 10→ *
 11→ * Driving ports:
 12→ *   POST /api/workspaces                           (create with repo_path)
 13→ *   POST /api/workspaces/:ws/repo-path             (set/update repo_path)
 14→ *   POST /api/orchestrator/:ws/assign              (blocked without repo_path)
 15→ *   GET  /api/workspaces/:ws/bootstrap             (repo_path in response)
 16→ */
 17→import { describe, expect, it } from "bun:test";
 18→import {
 19→  setupOrchestratorSuite,
 20→  createTestUser,
 21→  createReadyTask,
 22→  assignTaskToAgent,
 23→  fetchRaw,
 24→  fetchJson,
 25→} from "./orchestrator-test-kit";
 26→
 27→const getRuntime = setupOrchestratorSuite("repo_path");
 28→
 29→// ---------------------------------------------------------------------------
 30→// Helper: create workspace with optional repo_path
 31→// ---------------------------------------------------------------------------
 32→
 33→type TestWorkspace = { workspaceId: string; conversationId: string };
 34→
 35→async function createWorkspaceWithRepoPath(
 36→  baseUrl: string,
 37→  user: { headers: Record<string, string> },
 38→  options?: { repoPath?: string },
 39→): Promise<TestWorkspace> {
 40→  return fetchJson<TestWorkspace>(`${baseUrl}/api/workspaces`, {
 41→    method: "POST",
 42→    headers: { "Content-Type": "application/json", ...user.headers },
 43→    body: JSON.stringify({
 44→      name: `Repo Path Test ${Date.now()}`,
 45→      ...(options?.repoPath ? { repoPath: options.repoPath } : {}),
 46→    }),
 47→  });
 48→}
 49→
 50→async function setRepoPath(
 51→  baseUrl: string,
 52→  user: { headers: Record<string, string> },
 53→  workspaceId: string,
 54→  path: string,
 55→): Promise<Response> {
 56→  return fetchRaw(`${baseUrl}/api/workspaces/${workspaceId}/repo-path`, {
 57→    method: "POST",
 58→    headers: { "Content-Type": "application/json", ...user.headers },
 59→    body: JSON.stringify({ path }),
 60→  });
 61→}
 62→
 63→// ---------------------------------------------------------------------------
 64→// US-2: Assignment blocked when repo_path is missing
 65→// ---------------------------------------------------------------------------
 66→
 67→describe("Repo Path: Assignment guard requires repo_path", () => {
 68→  it("rejects task assignment when workspace has no repo_path", async () => {
 69→    const { baseUrl, surreal } = getRuntime();
 70→
 71→    // Given a workspace created without a repo_path
 72→    const user = await createTestUser(baseUrl, "repo-none");
 73→    const workspace = await createWorkspaceWithRepoPath(baseUrl, user);
 74→    const task = await createReadyTask(surreal, workspace.workspaceId, {
 75→      title: "Build login page",
 76→    });
 77→
 78→    // When the user tries to assign the task to an agent
 79→    const response = await fetchRaw(
 80→      `${baseUrl}/api/orchestrator/${workspace.workspaceId}/assign`,
 81→      {
 82→        method: "POST",
 83→        headers: { "Content-Type": "application/json", ...user.headers },
 84→        body: JSON.stringify({ taskId: task.taskId }),
 85→      },
 86→    );
 87→
 88→    // Then the assignment is rejected because repo_path is not configured
 89→    expect(response.status).toBe(400);
 90→    const body = await response.json();
 91→    expect(body.error).toContain("repo_path");
 92→  }, 60_000);
 93→
 94→  it("allows task assignment after repo_path is set", async () => {
 95→    const { baseUrl, surreal } = getRuntime();
 96→
 97→    // Given a workspace initially created without a repo_path
 98→    const user = await createTestUser(baseUrl, "repo-set-later");
 99→    const workspace = await createWorkspaceWithRepoPath(baseUrl, user);
100→    const task = await createReadyTask(surreal, workspace.workspaceId, {
101→      title: "Add search endpoint",
102→    });
103→
104→    // And the user sets the repo_path to a valid git repository
105→    const repoPath = process.cwd(); // The test project itself is a git repo
106→    const setResponse = await setRepoPath(
107→      baseUrl,
108→      user,
109→      workspace.workspaceId,
110→      repoPath,
111→    );
112→    expect(setResponse.status).toBe(200);
113→
114→    // When the user assigns the task to an agent
115→    const assignment = await assignTaskToAgent(
116→      baseUrl,
117→      user,
118→      workspace.workspaceId,
119→      task.taskId,
120→    );
121→
122→    // Then the assignment succeeds
123→    expect(assignment.agentSessionId).toBeTruthy();
124→  }, 60_000);
125→});
126→
127→// ---------------------------------------------------------------------------
128→// US-1: Set repo_path during workspace creation
129→// ---------------------------------------------------------------------------
130→
131→describe("Repo Path: Set during workspace creation", () => {
132→  it("persists repo_path when provided during workspace creation", async () => {
133→    const { baseUrl } = getRuntime();
134→
135→    // Given a valid git repository path
136→    const repoPath = process.cwd();
137→    const user = await createTestUser(baseUrl, "repo-create");
138→
139→    // When the user creates a workspace with a repo_path
140→    const workspace = await createWorkspaceWithRepoPath(baseUrl, user, {
141→      repoPath,
142→    });
143→
144→    // Then the workspace bootstrap response includes the repo_path
145→    const bootstrap = await fetchJson<{ repoPath?: string }>(
146→      `${baseUrl}/api/workspaces/${workspace.workspaceId}/bootstrap`,
147→      { headers: user.headers },
148→    );
149→    expect(bootstrap.repoPath).toBe(repoPath);
150→  }, 60_000);
151→
152→  it("rejects workspace creation with an invalid repo_path", async () => {
153→    const { baseUrl } = getRuntime();
154→
155→    // Given a path that is not a git repository
156→    const user = await createTestUser(baseUrl, "repo-invalid");
157→
158→    // When the user creates a workspace with an invalid repo_path
159→    const response = await fetchRaw(`${baseUrl}/api/workspaces`, {
160→      method: "POST",
161→      headers: { "Content-Type": "application/json", ...user.headers },
162→      body: JSON.stringify({
163→        name: "Invalid Repo Test",
164→        repoPath: "/tmp/not-a-git-repo-" + Date.now(),
165→      }),
166→    });
167→
168→    // Then creation is rejected because the path is not a valid git repo
169→    expect(response.status).toBe(400);
170→  }, 60_000);
171→
172→  it("allows workspace creation without a repo_path", async () => {
173→    const { baseUrl } = getRuntime();
174→
175→    // Given no repo_path is provided
176→    const user = await createTestUser(baseUrl, "repo-optional");
177→
178→    // When the user creates a workspace without repo_path
179→    const workspace = await createWorkspaceWithRepoPath(baseUrl, user);
180→
181→    // Then the workspace is created successfully
182→    expect(workspace.workspaceId).toBeTruthy();
183→
184→    // And bootstrap response has no repoPath
185→    const bootstrap = await fetchJson<{ repoPath?: string }>(
186→      `${baseUrl}/api/workspaces/${workspace.workspaceId}/bootstrap`,
187→      { headers: user.headers },
188→    );
189→    expect(bootstrap.repoPath).toBeUndefined();
190→  }, 60_000);
191→});
192→
193→// ---------------------------------------------------------------------------
194→// US-3: Update repo_path on existing workspace
195→// ---------------------------------------------------------------------------
196→
197→describe("Repo Path: Update on existing workspace", () => {
198→  it("validates the path is a git repository when setting repo_path", async () => {
199→    const { baseUrl } = getRuntime();
200→
201→    const user = await createTestUser(baseUrl, "repo-validate");
202→    const workspace = await createWorkspaceWithRepoPath(baseUrl, user);
203→
204→    // When the user sets repo_path to a non-git directory
205→    const response = await setRepoPath(
206→      baseUrl,
207→      user,
208→      workspace.workspaceId,
209→      "/tmp/not-a-git-repo-" + Date.now(),
210→    );
211→
212→    // Then the update is rejected
213→    expect(response.status).toBe(400);
214→  }, 60_000);
215→
216→  it("validates the path exists when setting repo_path", async () => {
217→    const { baseUrl } = getRuntime();
218→
219→    const user = await createTestUser(baseUrl, "repo-noexist");
220→    const workspace = await createWorkspaceWithRepoPath(baseUrl, user);
221→
222→    // When the user sets repo_path to a nonexistent directory
223→    const response = await setRepoPath(
224→      baseUrl,
225→      user,
226→      workspace.workspaceId,
227→      "/nonexistent/path/that/does/not/exist",
228→    );
229→
230→    // Then the update is rejected
231→    expect(response.status).toBe(400);
232→  }, 60_000);
233→
234→  it("updates repo_path to a valid git repository", async () => {
235→    const { baseUrl } = getRuntime();
236→
237→    const user = await createTestUser(baseUrl, "repo-update");
238→    const workspace = await createWorkspaceWithRepoPath(baseUrl, user);
239→    const repoPath = process.cwd();
240→
241→    // When the user sets repo_path to a valid git repository
242→    const response = await setRepoPath(
243→      baseUrl,
244→      user,
245→      workspace.workspaceId,
246→      repoPath,
247→    );
248→
249→    // Then the update succeeds
250→    expect(response.status).toBe(200);
251→
252→    // And the bootstrap response reflects the updated path
253→    const bootstrap = await fetchJson<{ repoPath?: string }>(
254→      `${baseUrl}/api/workspaces/${workspace.workspaceId}/bootstrap`,
255→      { headers: user.headers },
256→    );
257→    expect(bootstrap.repoPath).toBe(repoPath);
258→  }, 60_000);
259→});
