 59→async function handleCreateWorkspace(deps: ServerDependencies, request: Request): Promise<Response> {
 60→  const startedAt = performance.now();
 61→  logInfo("workspace.create.started", "Workspace creation started");
 62→
 63→  const session = await deps.auth.api.getSession({ headers: request.headers });
 64→  if (!session?.user?.id) {
 65→    return jsonError("authentication required", 401);
 66→  }
 67→
 68→  let body: unknown;
 69→  try {
 70→    body = await request.json();
 71→  } catch {
 72→    return jsonError("Request body must be valid JSON", 400);
 73→  }
 74→
 75→  const parsed = parseCreateWorkspaceRequest(body);
 76→  if (!parsed.ok) {
 77→    return jsonError(parsed.error, 400);
 78→  }
 79→
 80→  logDebug("http.request.validated", "Workspace request validated");
 81→
 82→  const now = new Date();
 83→  const workspaceId = randomUUID();
 84→  const conversationId = randomUUID();
 85→
 86→  const workspaceRecord = new RecordId("workspace", workspaceId);
 87→  const conversationRecord = new RecordId("conversation", conversationId);
 88→  const ownerRecord = new RecordId("person", session.user.id);
 89→  const starterMessageRecord = new RecordId("message", randomUUID());
 90→  const hasDescription = parsed.data.description !== undefined;
 91→  const ownerName = session.user.name ?? "there";
 92→
 93→  const starterSuggestions = hasDescription
 94→    ? [
 95→        "Describe your first project",
 96→        "Share the biggest current bottleneck",
 97→        "Upload a plan or spec to extract",
 98→      ]
 99→    : [
100→        "Describe your business and goals",
101→        "Share the biggest current bottleneck",
102→        "Upload a plan or spec to extract",
103→      ];
104→
105→  const starterMessage = hasDescription
106→    ? [
107→        `Hey ${ownerName}!`,
108→        `Got it — I'll help you organize ${parsed.data.name}.`,
109→        "What are the main projects or product areas you want to track?",
110→        "You can also drop in a document (plan, spec, PRD) and I'll extract everything from it.",
111→      ].join(" ")
112→    : [
113→        `Hey ${ownerName}!`,
114→        "I'm ready to help you build out your workspace.",
115→        "Tell me about what you're working on - what's the main project or business you want to track here?",
116→        "If you have an existing document (like a plan or spec), you can drop it in and I'll extract everything from it.",
117→      ].join(" ");
118→
119→  const transaction = await deps.surreal.beginTransaction();
120→  try {
121→    await transaction.create(workspaceRecord).content({
122→      name: parsed.data.name,
123→      ...(parsed.data.description ? { description: parsed.data.description } : {}),
124→      status: "active",
125→      onboarding_complete: false,
126→      onboarding_turn_count: 0,
127→      onboarding_summary_pending: false,
128→      onboarding_started_at: now,
129→      created_at: now,
130→      updated_at: now,
131→    });
132→
133→    await transaction.relate(ownerRecord, new RecordId("member_of", randomUUID()), workspaceRecord, {
134→      role: "owner",
135→      added_at: now,
136→    }).output("after");
137→
138→    await transaction.create(conversationRecord).content({
139→      createdAt: now,
140→      updatedAt: now,
141→      workspace: workspaceRecord,
142→      source: "onboarding",
143→      title: "Onboarding",
144→      title_source: "message",
145→    });
146→
147→    await transaction.create(starterMessageRecord).content({
148→      conversation: conversationRecord,
149→      role: "assistant",
150→      text: starterMessage,
151→      suggestions: starterSuggestions,
152→      createdAt: now,
153→    });
154→
155→    await transaction.commit();
156→  } catch (error) {
157→    await transaction.cancel();
158→    logError("workspace.create.failed", "Workspace creation failed", error, {
159→      workspaceId,
160→      conversationId,
161→    });
162→    const errorText = error instanceof Error ? error.message : "workspace creation failed";
163→    return jsonError(errorText, 500);
164→  }
165→
166→  const response: CreateWorkspaceResponse = {
167→    workspaceId,
168→    workspaceName: parsed.data.name,
169→    conversationId,
170→    onboardingComplete: false,
171→  };
172→
173→  logInfo("workspace.create.completed", "Workspace creation completed", {
174→    workspaceId,
175→    conversationId,
176→    durationMs: elapsedMs(startedAt),
177→  });
178→
179→  return jsonResponse(response, 200);
180→}
