172→async function parseIncomingAttachment(file: File): Promise<IncomingAttachment> {
173→  if (file.size > MAX_UPLOAD_BYTES) {
174→    throw new HttpError(400, `file is too large, max size is ${MAX_UPLOAD_BYTES} bytes`);
175→  }
176→
177→  const extension = file.name.split(".").pop()?.toLowerCase();
178→  if (!extension || !allowedUploadExtensions.has(extension)) {
179→    throw new HttpError(400, "only .md and .txt files are supported in phase 1");
180→  }
181→
182→  const content = (await file.text()).trim();
183→  if (content.length === 0) {
184→    throw new HttpError(400, "uploaded file content is empty");
185→  }
186→
187→  return {
188→    fileName: file.name,
189→    mimeType: file.type.trim().length > 0 ? file.type : "text/plain",
190→    sizeBytes: file.size,
191→    content,
192→  };
193→}
