 98→async function hasActiveSession(
 99→  surreal: Surreal,
100→  taskRecord: RecordId<"task", string>,
101→): Promise<boolean> {
102→  const [rows] = await surreal.query<[ActiveSessionRow[]]>(
103→    `SELECT id, orchestrator_status FROM agent_session
104→     WHERE task_id = $taskRecord
105→       AND orchestrator_status IN $activeStatuses
106→     LIMIT 1;`,
107→    { taskRecord, activeStatuses: [...ACTIVE_ORCHESTRATOR_STATUSES] },
108→  );
109→  return rows.length > 0;
110→}
