 64→// ---------------------------------------------------------------------------
 65→// Status badge display
 66→// ---------------------------------------------------------------------------
 67→
 68→const STATUS_LABELS: Record<AgentSessionStatus, string> = {
 69→  spawning: "Spawning",
 70→  active: "Working",
 71→  idle: "Idle",
 72→  completed: "Completed",
 73→  aborted: "Aborted",
 74→  error: "Error",
 75→};
 76→
 77→function statusLabel(status: AgentSessionStatus): string {
 78→  return STATUS_LABELS[status];
 79→}
