 81→// ---------------------------------------------------------------------------
 82→// Component
 83→// ---------------------------------------------------------------------------
 84→
 85→export function AgentStatusSection({
 86→  entityId,
 87→  workspaceId,
 88→  entityKind,
 89→  entityStatus,
 90→  agentSession,
 91→}: {
 92→  entityId: string;
 93→  workspaceId: string;
 94→  entityKind: EntityKind;
 95→  entityStatus: string;
 96→  agentSession?: AgentSessionSummary;
 97→}) {
 98→  const [assigning, setAssigning] = useState(false);
 99→  const [assignError, setAssignError] = useState<string | undefined>();
100→  const [assignResult, setAssignResult] = useState<AssignAgentResponse | undefined>();
101→
102→  // Derive the initial view from props
103→  const initialView = deriveAgentStatusView({ entityKind, entityStatus, agentSession });
104→
105→  // If we have an assign result, use its stream URL; otherwise use session from props.
106→  // streamUrl is a dependency of useAgentSession's useEffect, so when assignResult
107→  // arrives and triggers a re-render, the hook will start the SSE subscription.
108→  const streamUrl = assignResult?.streamUrl ?? (initialView.variant === "active" ? initialView.streamUrl : undefined);
109→  const startedAt = initialView.variant === "active" ? initialView.startedAt : new Date().toISOString();
110→
111→  // SSE subscription -- only active when we have a stream URL
112→  const { state: sessionState } = useAgentSession(streamUrl, startedAt);
113→
114→  // Determine what to show
115→  const hasActiveStream = streamUrl !== undefined;
116→
117→  if (initialView.variant === "hidden" && !hasActiveStream) {
118→    return undefined;
119→  }
120→
121→  async function handleAssign() {
122→    if (assigning) return;
123→    setAssigning(true);
124→    setAssignError(undefined);
125→    try {
126→      const result = await assignAgent(workspaceId, entityId);
127→      setAssignResult(result);
128→    } catch (err) {
129→      setAssignError(err instanceof Error ? err.message : "Failed to assign agent");
130→    } finally {
131→      setAssigning(false);
132→    }
133→  }
134→
135→  // Show active session view (either from props or from fresh assignment)
136→  if (hasActiveStream) {
137→    const displayStatus = sessionState.status;
138→    const displayFiles = initialView.variant === "active"
139→      ? initialView.filesChangedCount + sessionState.filesChanged
140→      : sessionState.filesChanged;
141→
142→    return (
143→      <div className="entity-detail-section agent-status-section">
144→        <h4>Agent</h4>
145→        <div className="agent-status-row">
146→          <span className={`agent-status-badge agent-status-${displayStatus}`} data-testid="agent-status-badge">
147→            {statusLabel(displayStatus)}
148→          </span>
149→          {displayFiles > 0 ? (
150→            <span className="agent-file-count" data-testid="agent-file-count">
151→              {displayFiles} file{displayFiles !== 1 ? "s" : ""} changed
152→            </span>
153→          ) : undefined}
154→        </div>
155→        {sessionState.stallWarning ? (
156→          <p className="agent-stall-warning" data-testid="agent-stall-warning">
157→            Agent may be stalled (no activity for {sessionState.stallWarning.stallDurationSeconds}s)
158→          </p>
159→        ) : undefined}
160→        {sessionState.connectionError ? (
161→          <p className="agent-connection-error">{sessionState.connectionError}</p>
162→        ) : undefined}
163→        {displayStatus === "idle" ? (
164→          <a
165→            className="agent-review-link"
166→            data-testid="agent-review-link"
167→            href={`/review/${encodeURIComponent(
168→              assignResult?.agentSessionId
169→                ?? (initialView.variant === "active" ? initialView.agentSessionId : ""),
170→            )}`}
171→          >
172→            Review
173→          </a>
174→        ) : undefined}
175→      </div>
176→    );
177→  }
178→
179→  // Show assign button
180→  if (initialView.variant === "assign") {
181→    return (
182→      <div className="entity-detail-section agent-status-section">
183→        <h4>Agent</h4>
184→        <button
185→          type="button"
186→          className="agent-assign-button"
187→          data-testid="agent-assign-button"
188→          disabled={assigning}
189→          onClick={handleAssign}
190→        >
191→          {assigning ? "Assigning..." : "Assign Agent"}
192→        </button>
193→        {assignError ? (
194→          <p className="agent-assign-error" data-testid="agent-assign-error">{assignError}</p>
195→        ) : undefined}
196→      </div>
197→    );
198→  }
199→
200→  return undefined;
201→}
