  1→import { FormEvent, useEffect, useState } from "react";
  2→import type { UIMessage } from "ai";
  3→import type {
  4→  CreateWorkspaceRequest,
  5→  CreateWorkspaceResponse,
  6→  WorkspaceBootstrapMessage,
  7→  WorkspaceBootstrapResponse,
  8→} from "../../shared/contracts";
  9→import { useWorkspaceState, type BootstrapPayload } from "../stores/workspace-state";
 10→
 11→const ACTIVE_WORKSPACE_STORAGE_KEY = "brain.activeWorkspaceId";
 12→
 13→type UseWorkspaceReturn = {
 14→  isReady: boolean;
 15→  isBootstrapping: boolean;
 16→  isCreatingWorkspace: boolean;
 17→  errorMessage?: string;
 18→  createWorkspaceName: string;
 19→  createWorkspaceDescription: string;
 20→  canCreateWorkspace: boolean;
 21→  setCreateWorkspaceName: (name: string) => void;
 22→  setCreateWorkspaceDescription: (description: string) => void;
 23→  onCreateWorkspace: (event: FormEvent<HTMLFormElement>) => void;
 24→};
 25→
 26→function bootstrapMessagesToUIMessages(messages: WorkspaceBootstrapMessage[]): UIMessage[] {
 27→  return messages.map((m) => ({
 28→    id: m.id,
 29→    role: m.role,
 30→    parts: [{ type: "text" as const, text: m.text }],
 31→    createdAt: new Date(m.createdAt),
 32→  }));
 33→}
 34→
 35→function parseBootstrapMessages(payload: WorkspaceBootstrapResponse): BootstrapPayload {
 36→  return { messages: bootstrapMessagesToUIMessages(payload.messages) };
 37→}
 38→
 39→export { parseBootstrapMessages, ACTIVE_WORKSPACE_STORAGE_KEY };
 40→
 41→export function useWorkspace(): UseWorkspaceReturn {
 42→  const store = useWorkspaceState();
 43→  const [createWorkspaceName, setCreateWorkspaceName] = useState("");
 44→  const [createWorkspaceDescription, setCreateWorkspaceDescription] = useState("");
 45→  const [isCreatingWorkspace, setIsCreatingWorkspace] = useState(false);
 46→  const [errorMessage, setErrorMessage] = useState<string | undefined>();
 47→
 48→  const canCreateWorkspace = createWorkspaceName.trim().length > 0;
 49→
 50→  useEffect(() => {
 51→    const existingWorkspaceId = window.localStorage.getItem(ACTIVE_WORKSPACE_STORAGE_KEY);
 52→    if (!existingWorkspaceId) {
 53→      return;
 54→    }
 55→
 56→    void bootstrapWorkspace(existingWorkspaceId);
 57→  }, []);
 58→
 59→  async function bootstrapWorkspace(workspaceId: string) {
 60→    store.setIsBootstrapping(true);
 61→    setErrorMessage(undefined);
 62→
 63→    let response: Response;
 64→    try {
 65→      response = await fetch(`/api/workspaces/${encodeURIComponent(workspaceId)}/bootstrap`);
 66→    } catch (error) {
 67→      const messageText = error instanceof Error ? error.message : "Network error";
 68→      setErrorMessage(messageText);
 69→      store.setIsBootstrapping(false);
 70→      return;
 71→    }
 72→
 73→    if (!response.ok) {
 74→      if (response.status === 404) {
 75→        window.localStorage.removeItem(ACTIVE_WORKSPACE_STORAGE_KEY);
 76→        store.clearWorkspace();
 77→      }
 78→      const body = await response.text();
 79→      setErrorMessage(body);
 80→      store.setIsBootstrapping(false);
 81→      return;
 82→    }
 83→
 84→    const payload = (await response.json()) as WorkspaceBootstrapResponse;
 85→    applyBootstrapPayload(payload);
 86→    store.setIsBootstrapping(false);
 87→  }
 88→
 89→  function applyBootstrapPayload(payload: WorkspaceBootstrapResponse) {
 90→    const parsed = parseBootstrapMessages(payload);
 91→
 92→    store.setSeedItems(payload.seeds);
 93→    store.setSidebar(payload.sidebar);
 94→    store.setBootstrapPayload(parsed);
 95→    store.applyWorkspace({
 96→      id: payload.workspaceId,
 97→      name: payload.workspaceName,
 98→      onboardingComplete: payload.onboardingComplete,
 99→      onboardingState: payload.onboardingState,
100→      conversationId: payload.conversationId,
101→    });
102→  }
103→
104→  async function onCreateWorkspace(event: FormEvent<HTMLFormElement>) {
105→    event.preventDefault();
106→
107→    const name = createWorkspaceName.trim();
108→    if (isCreatingWorkspace) {
109→      return;
110→    }
111→
112→    if (!name) {
113→      setErrorMessage("Workspace name is required");
114→      return;
115→    }
116→
117→    setErrorMessage(undefined);
118→    setIsCreatingWorkspace(true);
119→
120→    const description = createWorkspaceDescription.trim();
121→    const requestBody: CreateWorkspaceRequest = {
122→      name,
123→      ...(description.length > 0 ? { description } : {}),
124→    };
125→
126→    try {
127→      const response = await fetch("/api/workspaces", {
128→        method: "POST",
129→        headers: {
130→          "Content-Type": "application/json",
131→        },
132→        body: JSON.stringify(requestBody),
133→      });
134→
135→      if (!response.ok) {
136→        const body = await response.text();
137→        setErrorMessage(body);
138→        return;
139→      }
140→
141→      const payload = (await response.json()) as Partial<CreateWorkspaceResponse>;
142→      if (typeof payload.workspaceId !== "string" || payload.workspaceId.trim().length === 0) {
143→        throw new Error("create workspace response is missing workspaceId");
144→      }
145→
146→      window.localStorage.setItem(ACTIVE_WORKSPACE_STORAGE_KEY, payload.workspaceId);
147→      await bootstrapWorkspace(payload.workspaceId);
148→      setCreateWorkspaceName("");
149→      setCreateWorkspaceDescription("");
150→    } catch (error) {
151→      const messageText = error instanceof Error ? error.message : "Workspace creation failed";
152→      setErrorMessage(messageText);
153→    } finally {
154→      setIsCreatingWorkspace(false);
155→    }
156→  }
157→
158→  return {
159→    isReady: store.workspaceId !== undefined && !store.isBootstrapping,
160→    isBootstrapping: store.isBootstrapping,
161→    isCreatingWorkspace,
162→    errorMessage,
163→    createWorkspaceName,
164→    createWorkspaceDescription,
165→    canCreateWorkspace,
166→    setCreateWorkspaceName,
167→    setCreateWorkspaceDescription,
168→    onCreateWorkspace,
169→  };
170→}
