 13→export function ChatPage() {
 14→  const onboardingState = useWorkspaceState((s) => s.onboardingState);
 15→  const setSidebarHandlers = useWorkspaceState((s) => s.setSidebarHandlers);
 16→
 17→  // Read conversationId from /chat/$conversationId route (undefined on /chat)
 18→  const matchWithId = useMatch({ from: "/authenticated/chat/$conversationId", shouldThrow: false });
 19→  const routeConversationId = matchWithId?.params.conversationId;
 20→
 21→  // Read message search param (works on both /chat and /chat/:id)
 22→  const search = useSearch({ strict: false });
 23→  const messageParam = (search as { message?: string })?.message;
 24→
 25→  const chat = useChatSession(routeConversationId);
 26→  const { feed } = useGovernanceFeed();
 27→
 28→  // Keep a ref to the latest chat handlers so the effect below doesn't
 29→  // depend on unstable function references.
 30→  const chatRef = useRef(chat);
 31→  chatRef.current = chat;
 32→
 33→  // Register sidebar handlers so the shell sidebar can interact with chat
 34→  useEffect(() => {
 35→    setSidebarHandlers({
 36→      activeConversationId: chat.activeConversationId,
 37→      isLoading: chat.isLoading,
 38→      onNewConversation: () => chatRef.current.newConversation(),
 39→      onSelectConversation: (id: string) => chatRef.current.selectConversation(id),
 40→    });
 41→  }, [chat.activeConversationId, chat.isLoading]);
 42→
 43→  // Cleanup sidebar handlers on unmount
 44→  useEffect(() => {
 45→    return () => {
 46→      setSidebarHandlers(undefined);
 47→    };
 48→  }, []);
 49→
 50→  // Load conversation from URL param on mount/param change
 51→  useEffect(() => {
 52→    if (routeConversationId && routeConversationId !== chat.activeConversationId) {
 53→      chat.selectConversation(routeConversationId);
 54→    } else if (!routeConversationId && chat.activeConversationId) {
 55→      // Navigated from /chat/:id to /chat (e.g., discuss on new chat)
 56→      chat.resetChat();
 57→    }
 58→  }, [routeConversationId]);
 59→
 60→  // Scroll to message from ?message= search param
 61→  useEffect(() => {
 62→    if (!messageParam) return;
 63→
 64→    const timer = setTimeout(() => {
 65→      const element = document.querySelector(`[data-message-id="${CSS.escape(messageParam)}"]`);
 66→      if (element) {
 67→        element.scrollIntoView({ behavior: "smooth", block: "center" });
 68→        element.classList.add("animate-highlight");
 69→        element.addEventListener("animationend", () => {
 70→          element.classList.remove("animate-highlight");
 71→        }, { once: true });
 72→      }
 73→    }, 100);
 74→
 75→    return () => clearTimeout(timer);
 76→  }, [messageParam, chat.messages]);
 77→
 78→  // Auto-scroll to bottom (skip when targeting a specific message)
 79→  const messagesEndRef = useRef<HTMLDivElement>(null);
 80→  useEffect(() => {
 81→    if (messageParam) return;
 82→    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
 83→  }, [chat.messages]);
 84→
 85→  return (
 86→    <section className="chat-page">
 87→      {(chat.discussEntity ?? chat.conversationDiscussEntity) ? (
 88→        <DiscussEntityCard
 89→          entity={(chat.discussEntity ?? chat.conversationDiscussEntity) as DiscussEntitySummary}
 90→        />
 91→      ) : undefined}
 92→
 93→      <div className="chat-messages">
 94→        {chat.messages.length === 0
 95→          && onboardingState === "complete"
 96→          && !chat.discussEntity
 97→          && !chat.conversationDiscussEntity ? (
 98→          <ChatSuggestionPills feed={feed} />
 99→        ) : undefined}
100→        {chat.messages.map((message) => (
101→          <div
102→            key={message.id}
103→            data-message-id={message.id}
104→            className={`chat-message chat-message--${message.role}`}
105→          >
106→            {message.role === "user" ? (
107→              <div className="chat-message-label">You</div>
108→            ) : undefined}
109→            {message.parts.map((part, i) => {
110→              if (part.type === "text") {
111→                return (
112→                  <div key={i} className="chat-message-text">
113→                    <Markdown components={{ a: EntityLink }}>{part.text}</Markdown>
114→                  </div>
115→                );
116→              }
117→              if (part.type === "reasoning") {
118→                return (
119→                  <details key={i} className="thinking-block">
120→                    <summary>Thinking</summary>
121→                    <pre className="thinking-content">{part.text}</pre>
122→                  </details>
123→                );
124→              }
125→              if (isToolPart(part)) {
126→                const toolPart = part as { type: string; state: string; output?: unknown };
127→                const toolName = toolPart.type.replace(/^tool-/, "");
128→
129→                if (toolName === "create_suggestion" && toolPart.state === "output-available" && toolPart.output) {
130→                  const output = toolPart.output as { text: string; category: string; confidence: number; rationale: string; target?: string };
131→                  return <SuggestionToolCard key={i} output={output} />;
132→                }
133→
134→                if (toolName === "invoke_pm_agent" && toolPart.state === "output-available") {
135→                  const trace = (toolPart.output as Record<string, unknown> | undefined)?.trace as SubagentTrace | undefined;
136→                  if (trace) {
137→                    return (
138→                      <details key={i} className="subagent-trace-block">
139→                        <summary className="subagent-trace-summary">
140→                          PM Agent — {trace.intent.replace(/_/g, " ")} ({trace.steps.filter(s => s.type === "tool_call").length} tools, {(trace.totalDurationMs / 1000).toFixed(1)}s)
141→                        </summary>
142→                        <div className="subagent-trace-steps">
143→                          {trace.steps.map((step, j) => {
144→                            if (step.type === "text") {
145→                              return <div key={j} className="subagent-trace-text">{step.text}</div>;
146→                            }
147→                            return (
148→                              <details key={j} className="subagent-trace-step">
149→                                <summary className="subagent-trace-step-summary">
150→                                  <span className="subagent-trace-tool">{step.toolName}</span>
151→                                  {step.durationMs ? <span className="subagent-trace-duration">{step.durationMs}ms</span> : undefined}
152→                                </summary>
153→                                <pre className="subagent-trace-args">{step.argsJson}</pre>
154→                                <pre className="subagent-trace-result">{step.resultJson}</pre>
155→                              </details>
156→                            );
157→                          })}
158→                        </div>
159→                      </details>
160→                    );
161→                  }
162→                }
163→
164→                return (
165→                  <div key={i} className="chat-tool-invocation">
166→                    <span className="chat-tool-name">{toolName}</span>
167→                    {toolPart.state === "output-available" ? (
168→                      <span className="chat-tool-status">Done</span>
169→                    ) : (
170→                      <span className="chat-tool-status chat-tool-status--running">Running...</span>
171→                    )}
172→                  </div>
173→                );
174→              }
175→              return undefined;
176→            })}
177→            {message.role === "assistant" ? (
178→              <button
179→                type="button"
180→                className="branch-message-btn"
181→                onClick={() => void chat.branchFromMessage(message.id)}
182→                disabled={chat.isLoading || chat.branchingFromId !== undefined}
183→                title="Branch from here"
184→              >
185→                <svg width="16" height="16" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
186→                  <path d="M5 3v4.5c0 1.1.9 2 2 2h2.5M5 3L3 5M5 3l2 2M11 5v4.5c0 1.1-.9 2-2 2H6.5M11 5l-2-2M11 5l2-2" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
187→                </svg>
188→              </button>
189→            ) : undefined}
190→          </div>
191→        ))}
192→        <div ref={messagesEndRef} />
193→      </div>
194→
195→      {onboardingState === "summary_pending" ? (
196→        <div className="onboarding-action-buttons">
197→          <button
198→            type="button"
199→            disabled={chat.isLoading}
200→            onClick={() =>
201→              chat.sendMessage("Looks good, let's go.", {
202→                onboardingAction: "finalize_onboarding",
203→              })}
204→          >
205→            Looks good, let's go
206→          </button>
207→          <button
208→            type="button"
209→            disabled={chat.isLoading}
210→            onClick={() =>
211→              chat.sendMessage("I want to add more.", {
212→                onboardingAction: "continue_onboarding",
213→              })}
214→          >
215→            I want to add more
216→          </button>
217→        </div>
218→      ) : undefined}
219→
220→      <ChatInput
221→        onSend={chat.sendMessage}
222→        disabled={chat.isLoading}
223→        onStop={chat.stopMessage}
224→        isStreaming={chat.status === "streaming"}
225→      />
226→
227→      {chat.errorMessage ? <p className="error-message">{chat.errorMessage}</p> : undefined}
228→    </section>
229→  );
230→}
231→
232→function isToolPart(part: { type: string }): boolean {
233→  return part.type.startsWith("tool-");
234→}
235→
236→function ChatInput({
237→  onSend,
238→  disabled,
239→  onStop,
240→  isStreaming,
241→}: {
242→  onSend: (text: string) => void;
243→  disabled: boolean;
244→  onStop: () => void;
245→  isStreaming: boolean;
246→}) {
247→  const [input, setInput] = useState("");
248→  const textareaRef = useRef<HTMLTextAreaElement>(null);
249→
250→  function handleSubmit() {
251→    const trimmed = input.trim();
252→    if (!trimmed || disabled) return;
253→    onSend(trimmed);
254→    setInput("");
255→    // Reset textarea height
256→    if (textareaRef.current) {
257→      textareaRef.current.style.height = "auto";
258→    }
259→  }
260→
261→  function handleKeyDown(e: KeyboardEvent<HTMLTextAreaElement>) {
262→    if (e.key === "Enter" && !e.shiftKey) {
263→      e.preventDefault();
264→      handleSubmit();
265→    }
266→  }
267→
268→  // Auto-resize textarea
269→  useEffect(() => {
270→    const textarea = textareaRef.current;
271→    if (!textarea) return;
272→    textarea.style.height = "auto";
273→    textarea.style.height = `${Math.min(textarea.scrollHeight, 200)}px`;
274→  }, [input]);
275→
276→  return (
277→    <div className="chat-input-container">
278→      <textarea
279→        ref={textareaRef}
280→        className="chat-input"
281→        value={input}
282→        onChange={(e) => setInput(e.target.value)}
283→        onKeyDown={handleKeyDown}
284→        placeholder="Discuss tasks, decisions, and questions..."
285→        rows={1}
286→        disabled={disabled && !isStreaming}
287→      />
288→      {isStreaming ? (
289→        <button
290→          type="button"
291→          className="chat-input-btn chat-input-btn--stop"
292→          onClick={onStop}
293→          title="Stop"
294→        >
295→          Stop
296→        </button>
297→      ) : (
298→        <button
299→          type="button"
300→          className="chat-input-btn chat-input-btn--send"
301→          onClick={handleSubmit}
302→          disabled={disabled || input.trim().length === 0}
303→          title="Send"
304→        >
305→          Send
306→        </button>
307→      )}
308→    </div>
309→  );
310→}
