 52→export const useWorkspaceState = create<WorkspaceStateStore>((set, get) => ({
 53→  workspaceId: undefined,
 54→  workspaceName: undefined,
 55→  onboardingComplete: false,
 56→  onboardingState: undefined,
 57→  conversationId: undefined,
 58→  sidebar: undefined,
 59→  seedItems: [],
