 64→  setWorkspaceId: (workspaceId) => set({ workspaceId }),
 65→  setWorkspaceName: (name) => set({ workspaceName: name }),
 66→  setOnboardingState: (onboardingState) =>
 67→    set({ onboardingState, onboardingComplete: onboardingState === "complete" }),
 68→  setConversationId: (conversationId) => set({ conversationId }),
 69→  setSidebar: (sidebar) => set({ sidebar }),
 70→  setSeedItems: (seedItems) => set({ seedItems }),
 71→  mergeSeedItems: (items) => {
