 29→// ---------------------------------------------------------------------------
 30→// Helper: create workspace with optional repo_path
 31→// ---------------------------------------------------------------------------
 32→
 33→type TestWorkspace = { workspaceId: string; conversationId: string };
 34→
 35→async function createWorkspaceWithRepoPath(
 36→  baseUrl: string,
 37→  user: { headers: Record<string, string> },
 38→  options?: { repoPath?: string },
 39→): Promise<TestWorkspace> {
 40→  return fetchJson<TestWorkspace>(`${baseUrl}/api/workspaces`, {
 41→    method: "POST",
 42→    headers: { "Content-Type": "application/json", ...user.headers },
 43→    body: JSON.stringify({
 44→      name: `Repo Path Test ${Date.now()}`,
 45→      ...(options?.repoPath ? { repoPath: options.repoPath } : {}),
 46→    }),
 47→  });
 48→}
 49→
 50→async function setRepoPath(
 51→  baseUrl: string,
 52→  user: { headers: Record<string, string> },
 53→  workspaceId: string,
 54→  path: string,
 55→): Promise<Response> {
 56→  return fetchRaw(`${baseUrl}/api/workspaces/${workspaceId}/repo-path`, {
 57→    method: "POST",
 58→    headers: { "Content-Type": "application/json", ...user.headers },
 59→    body: JSON.stringify({ path }),
 60→  });
 61→}
 62→
 63→// ---------------------------------------------------------------------------
 64→// US-2: Assignment blocked when repo_path is missing
 65→// ---------------------------------------------------------------------------
 66→
 67→describe("Repo Path: Assignment guard requires repo_path", () => {
 68→  it("rejects task assignment when workspace has no repo_path", async () => {
 69→    const { baseUrl, surreal } = getRuntime();
 70→
 71→    // Given a workspace created without a repo_path
 72→    const user = await createTestUser(baseUrl, "repo-none");
 73→    const workspace = await createWorkspaceWithRepoPath(baseUrl, user);
 74→    const task = await createReadyTask(surreal, workspace.workspaceId, {
 75→      title: "Build login page",
 76→    });
 77→
 78→    // When the user tries to assign the task to an agent
 79→    const response = await fetchRaw(
 80→      `${baseUrl}/api/orchestrator/${workspace.workspaceId}/assign`,
 81→      {
 82→        method: "POST",
 83→        headers: { "Content-Type": "application/json", ...user.headers },
 84→        body: JSON.stringify({ taskId: task.taskId }),
 85→      },
 86→    );
 87→
 88→    // Then the assignment is rejected because repo_path is not configured
 89→    expect(response.status).toBe(400);
 90→    const body = await response.json();
 91→    expect(body.error).toContain("repo_path");
 92→  }, 60_000);
 93→
 94→  it("allows task assignment after repo_path is set", async () => {
 95→    const { baseUrl, surreal } = getRuntime();
 96→
 97→    // Given a workspace initially created without a repo_path
 98→    const user = await createTestUser(baseUrl, "repo-set-later");
 99→    const workspace = await createWorkspaceWithRepoPath(baseUrl, user);
100→    const task = await createReadyTask(surreal, workspace.workspaceId, {
101→      title: "Add search endpoint",
102→    });
103→
104→    // And the user sets the repo_path to a valid git repository
105→    const repoPath = process.cwd(); // The test project itself is a git repo
106→    const setResponse = await setRepoPath(
107→      baseUrl,
108→      user,
109→      workspace.workspaceId,
110→      repoPath,
111→    );
112→    expect(setResponse.status).toBe(200);
113→
114→    // When the user assigns the task to an agent
115→    const assignment = await assignTaskToAgent(
116→      baseUrl,
117→      user,
118→      workspace.workspaceId,
119→      task.taskId,
120→    );
121→
122→    // Then the assignment succeeds
123→    expect(assignment.agentSessionId).toBeTruthy();
124→  }, 60_000);
125→});
