  1→import { RecordId, type Surreal } from "surrealdb";
  2→import {
  3→  ASSIGNABLE_TASK_STATUSES,
  4→  ACTIVE_ORCHESTRATOR_STATUSES,
  5→  type AssignableTaskStatus,
  6→  type AssignmentError,
  7→  type AssignmentValidation,
  8→  type TaskRow,
  9→  type ActiveSessionRow,
 10→} from "./types";
 11→
 12→// ---------------------------------------------------------------------------
 13→// Result type — discriminated union for success/failure
 14→// ---------------------------------------------------------------------------
 15→
 16→export type AssignmentResult =
 17→  | { ok: true; validation: AssignmentValidation }
 18→  | { ok: false; error: AssignmentError };
 19→
 20→// ---------------------------------------------------------------------------
 21→// Pure helpers
 22→// ---------------------------------------------------------------------------
 23→
 24→function isAssignableStatus(status: string): status is AssignableTaskStatus {
 25→  return (ASSIGNABLE_TASK_STATUSES as readonly string[]).includes(status);
 26→}
 27→
 28→function missingTaskId(): AssignmentResult {
 29→  return {
 30→    ok: false,
 31→    error: {
 32→      code: "MISSING_TASK_ID",
 33→      message: "taskId is required",
 34→      httpStatus: 400,
 35→    },
 36→  };
 37→}
 38→
 39→function taskNotFound(taskId: string): AssignmentResult {
 40→  return {
 41→    ok: false,
 42→    error: {
 43→      code: "TASK_NOT_FOUND",
 44→      message: `Task not found: ${taskId}`,
 45→      httpStatus: 404,
 46→    },
 47→  };
 48→}
 49→
 50→function workspaceMismatch(taskId: string): AssignmentResult {
 51→  return {
 52→    ok: false,
 53→    error: {
 54→      code: "WORKSPACE_MISMATCH",
 55→      message: `Task ${taskId} does not belong to the requested workspace`,
 56→      httpStatus: 403,
 57→    },
 58→  };
 59→}
 60→
 61→function taskNotAssignable(taskId: string, status: string): AssignmentResult {
 62→  return {
 63→    ok: false,
 64→    error: {
 65→      code: "TASK_NOT_ASSIGNABLE",
 66→      message: `Task ${taskId} has status '${status}' and cannot be assigned (must be ready or todo)`,
 67→      httpStatus: 409,
 68→    },
 69→  };
 70→}
 71→
 72→function agentAlreadyActive(taskId: string): AssignmentResult {
 73→  return {
 74→    ok: false,
 75→    error: {
 76→      code: "AGENT_ALREADY_ACTIVE",
 77→      message: `Task ${taskId} already has an active agent session`,
 78→      httpStatus: 409,
 79→    },
 80→  };
 81→}
 82→
 83→// ---------------------------------------------------------------------------
 84→// DB queries (thin wrappers — side effects isolated here)
 85→// ---------------------------------------------------------------------------
 86→
 87→async function fetchTask(
 88→  surreal: Surreal,
 89→  taskRecord: RecordId<"task", string>,
 90→): Promise<TaskRow | undefined> {
 91→  const [rows] = await surreal.query<[TaskRow[]]>(
 92→    `SELECT id, title, status, workspace FROM $taskRecord;`,
 93→    { taskRecord },
 94→  );
 95→  return rows[0];
 96→}
 97→
 98→async function hasActiveSession(
 99→  surreal: Surreal,
100→  taskRecord: RecordId<"task", string>,
101→): Promise<boolean> {
102→  const [rows] = await surreal.query<[ActiveSessionRow[]]>(
103→    `SELECT id, orchestrator_status FROM agent_session
104→     WHERE task_id = $taskRecord
105→       AND orchestrator_status IN $activeStatuses
106→     LIMIT 1;`,
107→    { taskRecord, activeStatuses: [...ACTIVE_ORCHESTRATOR_STATUSES] },
108→  );
109→  return rows.length > 0;
110→}
111→
112→// ---------------------------------------------------------------------------
113→// Orchestration — pure pipeline over DB results
114→// ---------------------------------------------------------------------------
115→
116→/**
117→ * Validate that a task exists, is in an assignable status, belongs to the
118→ * given workspace, and has no active agent session already working on it.
119→ */
120→export async function validateAssignment(
121→  surreal: Surreal,
122→  workspaceId: string,
123→  taskId: string,
124→): Promise<AssignmentResult> {
125→  // 1. Input validation
126→  if (!taskId) {
127→    return missingTaskId();
128→  }
129→
130→  const taskRecord = new RecordId("task", taskId);
131→
132→  // 2. Task existence
133→  const task = await fetchTask(surreal, taskRecord);
134→  if (!task) {
135→    return taskNotFound(taskId);
136→  }
137→
138→  // 3. Workspace membership
139→  const taskWorkspaceId = task.workspace.id as string;
140→  if (taskWorkspaceId !== workspaceId) {
141→    return workspaceMismatch(taskId);
142→  }
143→
144→  // 4. Status eligibility
145→  if (!isAssignableStatus(task.status)) {
146→    return taskNotAssignable(taskId, task.status);
147→  }
148→
149→  // 5. One-agent-per-task
150→  const alreadyActive = await hasActiveSession(surreal, taskRecord);
151→  if (alreadyActive) {
152→    return agentAlreadyActive(taskId);
153→  }
154→
155→  // All checks passed
156→  return {
157→    ok: true,
158→    validation: {
159→      taskRecord,
160→      workspaceRecord: task.workspace,
161→      taskStatus: task.status,
162→      title: task.title,
163→    },
164→  };
165→}
