 92→// ---------------------------------------------------------------------------
 93→// In-memory handle registry — maps agentSessionId to OpenCodeHandle
 94→// ---------------------------------------------------------------------------
 95→
 96→const handleRegistry = new Map<string, OpenCodeHandle>();
 97→
 98→// Exported for testing cleanup
 99→export function clearHandleRegistry(): void {
100→  handleRegistry.clear();
101→}
102→
103→// ---------------------------------------------------------------------------
104→// Pure helpers
105→// ---------------------------------------------------------------------------
106→
107→function sessionNotFound(sessionId: string): SessionError {
108→  return {
109→    code: "SESSION_NOT_FOUND",
110→    message: `Session not found: ${sessionId}`,
111→    httpStatus: 404,
112→  };
113→}
114→
115→function worktreeError(message: string): SessionError {
116→  return {
117→    code: "WORKTREE_ERROR",
118→    message,
119→    httpStatus: 500,
120→  };
121→}
122→
123→function fromAssignmentError(error: AssignmentError): SessionError {
124→  return {
125→    code: error.code as SessionErrorCode,
126→    message: error.message,
127→    httpStatus: error.httpStatus,
128→  };
129→}
130→
131→type SessionLookup =
132→  | { ok: true; session: SessionRow; record: RecordId<"agent_session", string>; status: OrchestratorStatus }
133→  | { ok: false; error: SessionError };
134→
135→async function lookupSession(
136→  surreal: Surreal,
137→  sessionId: string,
138→): Promise<SessionLookup> {
139→  const record = new RecordId("agent_session", sessionId);
140→  const session = await surreal.select<SessionRow>(record);
141→  if (!session) {
142→    return { ok: false, error: sessionNotFound(sessionId) };
143→  }
144→  if (!session.orchestrator_status) {
145→    throw new Error(`agent_session ${sessionId} missing orchestrator_status — data corruption`);
146→  }
147→  const status = session.orchestrator_status as OrchestratorStatus;
148→  return { ok: true, session, record, status };
149→}
150→
151→function generateStreamId(sessionId: string): string {
152→  return `stream-${sessionId}`;
153→}
154→
155→function slugFromTitle(title: string): string {
156→  return title
157→    .toLowerCase()
158→    .replace(/[^a-z0-9]+/g, "-")
159→    .replace(/^-|-$/g, "")
160→    .slice(0, 50);
161→}
