163→// ---------------------------------------------------------------------------
164→// Session row shape (DB query result)
165→// ---------------------------------------------------------------------------
166→
167→type SessionRow = {
168→  id: RecordId<"agent_session", string>;
169→  orchestrator_status?: string;
170→  worktree_branch?: string;
171→  worktree_path?: string;
172→  started_at?: string;
173→  last_event_at?: string;
174→  task_id?: RecordId<"task", string>;
175→  workspace?: RecordId<"workspace", string>;
176→  error?: string;
177→};
178→
179→// ---------------------------------------------------------------------------
180→// createOrchestratorSession
181→// ---------------------------------------------------------------------------
182→
183→type CreateSessionInput = {
184→  surreal: Surreal;
185→  shellExec: ShellExec;
186→  repoRoot: string;
187→  brainBaseUrl: string;
188→  workspaceId: string;
189→  taskId: string;
190→  authToken: string;
191→  spawnOpenCode?: (
192→    config: OpencodeConfig,
193→    worktreePath: string,
194→  ) => Promise<OpenCodeHandle>;
195→  validateAssignment: (
196→    surreal: Surreal,
197→    workspaceId: string,
198→    taskId: string,
199→  ) => Promise<AssignmentResult>;
200→  createAgentSession: (input: {
201→    surreal: Surreal;
202→    agent: string;
203→    workspaceRecord: RecordId<"workspace", string>;
204→    taskId?: string;
205→  }) => Promise<{ session_id: string }>;
206→};
207→
208→export async function createOrchestratorSession(
209→  input: CreateSessionInput,
210→): Promise<OrchestratorSessionResult> {
211→  // 1. Validate assignment eligibility
212→  const assignmentResult = await input.validateAssignment(
213→    input.surreal,
214→    input.workspaceId,
215→    input.taskId,
216→  );
217→
218→  if (!assignmentResult.ok) {
219→    return { ok: false, error: fromAssignmentError(assignmentResult.error) };
220→  }
221→
222→  const { validation } = assignmentResult;
223→  const taskSlug = slugFromTitle(validation.title);
224→
225→  // 2. Create worktree
226→  const worktreeResult = await createWorktree(
227→    input.shellExec,
228→    input.repoRoot,
229→    taskSlug,
230→  );
231→
232→  if (!worktreeResult.ok) {
233→    return {
234→      ok: false,
235→      error: worktreeError(worktreeResult.error.message),
236→    };
237→  }
238→
239→  const { branchName, worktreePath } = worktreeResult.value;
240→
241→  // 3. Create agent_session record
242→  const { session_id: agentSessionId } = await input.createAgentSession({
243→    surreal: input.surreal,
244→    agent: "opencode",
245→    workspaceRecord: validation.workspaceRecord,
246→    taskId: input.taskId,
247→  });
248→
249→  const streamId = generateStreamId(agentSessionId);
250→
251→  // 4. Build config and spawn OpenCode
252→  const config = buildOpencodeConfig({
253→    brainBaseUrl: input.brainBaseUrl,
254→    workspaceId: input.workspaceId,
255→    authToken: input.authToken,
256→  });
257→
258→  const spawnFn = input.spawnOpenCode ?? defaultSpawnOpenCode;
259→  let handle: OpenCodeHandle;
260→  try {
261→    handle = await spawnFn(config, worktreePath);
262→  } catch (err) {
263→    // Rollback: remove worktree and delete agent_session on spawn failure
264→    await removeWorktree(input.shellExec, input.repoRoot, branchName);
265→    const sessionRecord = new RecordId("agent_session", agentSessionId);
266→    await input.surreal.delete(sessionRecord);
267→    return {
268→      ok: false,
269→      error: worktreeError(`Failed to spawn OpenCode: ${err instanceof Error ? err.message : String(err)}`),
270→    };
271→  }
272→
273→  // 5. Register handle for later abort
274→  handleRegistry.set(agentSessionId, handle);
275→
276→  // 6. Update agent_session with orchestrator fields
277→  const sessionRecord = new RecordId("agent_session", agentSessionId);
278→  await input.surreal.update(sessionRecord).merge({
279→    orchestrator_status: "spawning" as OrchestratorStatus,
280→    worktree_branch: branchName,
281→    worktree_path: worktreePath,
282→    opencode_session_id: handle.sessionId,
283→    stream_id: streamId,
284→  });
285→
286→  return {
287→    ok: true,
288→    value: {
289→      agentSessionId,
290→      streamId,
291→      worktreeBranch: branchName,
292→    },
293→  };
294→}
295→
296→// Default spawn -- placeholder for production use
297→async function defaultSpawnOpenCode(
298→  _config: OpencodeConfig,
299→  _worktreePath: string,
300→): Promise<OpenCodeHandle> {
301→  throw new Error(
302→    "spawnOpenCode not provided -- must be injected for production use",
303→  );
304→}
305→
306→// ---------------------------------------------------------------------------
307→// getOrchestratorSessionStatus
308→// ---------------------------------------------------------------------------
309→
310→type GetStatusInput = {
311→  surreal: Surreal;
312→  sessionId: string;
313→};
314→
315→export async function getOrchestratorSessionStatus(
316→  input: GetStatusInput,
317→): Promise<SessionStatusResult> {
318→  const lookup = await lookupSession(input.surreal, input.sessionId);
319→  if (!lookup.ok) {
320→    return { ok: false, error: lookup.error };
321→  }
322→  const { session } = lookup;
323→
324→  return {
325→    ok: true,
326→    value: {
327→      orchestratorStatus: lookup.status,
328→      ...(session.worktree_branch ? { worktreeBranch: session.worktree_branch } : {}),
329→      ...(session.worktree_path ? { worktreePath: session.worktree_path } : {}),
330→      ...(session.started_at ? { startedAt: session.started_at } : {}),
331→      ...(session.last_event_at ? { lastEventAt: session.last_event_at } : {}),
332→      ...(session.error ? { error: session.error } : {}),
333→    },
334→  };
335→}
336→
337→// ---------------------------------------------------------------------------
338→// abortOrchestratorSession
339→// ---------------------------------------------------------------------------
340→
341→type AbortSessionInput = {
342→  surreal: Surreal;
343→  shellExec: ShellExec;
344→  repoRoot: string;
345→  sessionId: string;
346→  endAgentSession: (input: {
347→    surreal: Surreal;
348→    workspaceRecord: RecordId<"workspace", string>;
349→    sessionId: string;
350→    summary: string;
351→  }) => Promise<{ session_id: string; ended: boolean }>;
352→};
353→
354→export async function abortOrchestratorSession(
355→  input: AbortSessionInput,
356→): Promise<AbortSessionResult> {
357→  const lookup = await lookupSession(input.surreal, input.sessionId);
358→  if (!lookup.ok) {
359→    return { ok: false, error: lookup.error };
360→  }
361→  const { session, record: sessionRecord } = lookup;
362→
363→  // 1. Kill the OpenCode process if handle exists
364→  const handle = handleRegistry.get(input.sessionId);
365→  if (handle) {
366→    handle.abort();
367→    handleRegistry.delete(input.sessionId);
368→  }
369→
370→  // 2. Update orchestrator_status to aborted
371→  await input.surreal.update(sessionRecord).merge({
372→    orchestrator_status: "aborted" as OrchestratorStatus,
373→  });
374→
375→  // 3. Remove worktree if branch name exists
376→  if (session.worktree_branch) {
377→    await removeWorktree(input.shellExec, input.repoRoot, session.worktree_branch);
378→  }
379→
380→  // 4. Return task to ready
381→  if (session.task_id) {
382→    await input.surreal.update(session.task_id).merge({
383→      status: "ready",
384→      updated_at: new Date(),
385→    });
386→  }
387→
388→  // 5. End the agent session
389→  if (!session.workspace) {
390→    throw new Error(`agent_session ${input.sessionId} missing workspace — data corruption`);
391→  }
392→  await input.endAgentSession({
393→    surreal: input.surreal,
394→    workspaceRecord: session.workspace as RecordId<"workspace", string>,
395→    sessionId: input.sessionId,
396→    summary: "Session aborted",
397→  });
398→
399→  return {
400→    ok: true,
401→    value: {
402→      aborted: true,
403→      sessionId: input.sessionId,
404→    },
405→  };
406→}
407→
408→// ---------------------------------------------------------------------------
409→// acceptOrchestratorSession
410→// ---------------------------------------------------------------------------
411→
412→type AcceptSessionInput = {
413→  surreal: Surreal;
414→  sessionId: string;
415→  summary: string;
416→  endAgentSession: (input: {
417→    surreal: Surreal;
418→    workspaceRecord: RecordId<"workspace", string>;
419→    sessionId: string;
420→    summary: string;
421→  }) => Promise<{ session_id: string; ended: boolean }>;
422→};
423→
424→export async function acceptOrchestratorSession(
425→  input: AcceptSessionInput,
426→): Promise<AcceptSessionResult> {
427→  const lookup = await lookupSession(input.surreal, input.sessionId);
428→  if (!lookup.ok) {
429→    return { ok: false, error: lookup.error };
430→  }
431→  const { session, record: sessionRecord, status } = lookup;
432→
433→  if (!ACCEPTABLE_STATUSES.includes(status)) {
434→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "accept") };
435→  }
436→
437→  // 1. Update orchestrator_status to completed
438→  await input.surreal.update(sessionRecord).merge({
439→    orchestrator_status: "completed" as OrchestratorStatus,
440→  });
441→
442→  // 2. Mark task as done
443→  if (session.task_id) {
444→    await input.surreal.update(session.task_id).merge({
445→      status: "done",
446→      updated_at: new Date(),
447→    });
448→  }
449→
450→  // 3. Clean up handle registry
451→  handleRegistry.delete(input.sessionId);
452→
453→  // 4. End the agent session
454→  if (!session.workspace) {
455→    throw new Error(`agent_session ${input.sessionId} missing workspace — data corruption`);
456→  }
457→  await input.endAgentSession({
458→    surreal: input.surreal,
459→    workspaceRecord: session.workspace as RecordId<"workspace", string>,
460→    sessionId: input.sessionId,
461→    summary: input.summary,
462→  });
463→
464→  return {
465→    ok: true,
466→    value: {
467→      accepted: true,
468→      sessionId: input.sessionId,
469→    },
470→  };
471→}
472→
473→// ---------------------------------------------------------------------------
474→// State guard helpers
475→// ---------------------------------------------------------------------------
476→
477→const REVIEWABLE_STATUSES: OrchestratorStatus[] = ["idle", "completed"];
478→const REJECTABLE_STATUSES: OrchestratorStatus[] = ["idle"];
479→const ACCEPTABLE_STATUSES: OrchestratorStatus[] = ["idle", "completed"];
480→
481→function sessionStateConflict(sessionId: string, currentStatus: string, action: string): SessionError {
482→  return {
483→    code: "SESSION_ERROR",
484→    message: `Cannot ${action} session ${sessionId}: current status is ${currentStatus}`,
485→    httpStatus: 409,
486→  };
487→}
488→
489→function sessionAborted(sessionId: string): SessionError {
490→  return {
491→    code: "SESSION_ERROR",
492→    message: `Session ${sessionId} has been aborted`,
493→    httpStatus: 409,
494→  };
495→}
496→
497→// ---------------------------------------------------------------------------
498→// getOrchestratorReview
499→// ---------------------------------------------------------------------------
500→
501→type GetReviewInput = {
502→  surreal: Surreal;
503→  sessionId: string;
504→  getDiff: (branchName: string) => Promise<import("./worktree-manager").WorktreeResult<import("./worktree-manager").DiffResult>>;
505→  getTaskTitle: (taskId: string) => Promise<string>;
506→};
507→
508→export async function getOrchestratorReview(
509→  input: GetReviewInput,
510→): Promise<ReviewResult> {
511→  const lookup = await lookupSession(input.surreal, input.sessionId);
512→  if (!lookup.ok) {
513→    return { ok: false, error: lookup.error };
514→  }
515→  const { session, status } = lookup;
516→
517→  if (status === "aborted") {
518→    return { ok: false, error: sessionAborted(input.sessionId) };
519→  }
520→
521→  if (!REVIEWABLE_STATUSES.includes(status)) {
522→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "review") };
523→  }
524→
525→  // Get diff from the branch
526→  const branchName = session.worktree_branch ?? "";
527→  const diffResult = await input.getDiff(branchName);
528→
529→  const diff = diffResult.ok
530→    ? diffResult.value
531→    : { files: [], rawDiff: "", stats: { filesChanged: 0, insertions: 0, deletions: 0 } };
532→
533→  // Get task title
534→  const taskId = session.task_id ? (session.task_id.id as string) : "";
535→  const taskTitle = taskId ? await input.getTaskTitle(taskId) : "";
536→
537→  return {
538→    ok: true,
539→    value: {
540→      taskTitle,
541→      diff,
542→      session: {
543→        orchestratorStatus: status,
544→        ...(session.worktree_branch ? { worktreeBranch: session.worktree_branch } : {}),
545→        ...(session.started_at ? { startedAt: session.started_at } : {}),
546→        ...(session.last_event_at ? { lastEventAt: session.last_event_at } : {}),
547→      },
548→    },
549→  };
550→}
551→
552→// ---------------------------------------------------------------------------
553→// rejectOrchestratorSession
554→// ---------------------------------------------------------------------------
555→
556→type RejectSessionInput = {
557→  surreal: Surreal;
558→  sessionId: string;
559→  feedback: string;
560→};
561→
562→export async function rejectOrchestratorSession(
563→  input: RejectSessionInput,
564→): Promise<RejectSessionResult> {
565→  const lookup = await lookupSession(input.surreal, input.sessionId);
566→  if (!lookup.ok) {
567→    return { ok: false, error: lookup.error };
568→  }
569→  const { session, record: sessionRecord, status } = lookup;
570→
571→  if (!REJECTABLE_STATUSES.includes(status)) {
572→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "reject") };
573→  }
574→
575→  // 1. Update session status to active (agent resumes work)
576→  await input.surreal.update(sessionRecord).merge({
577→    orchestrator_status: "active" as OrchestratorStatus,
578→    last_feedback: input.feedback,
579→  });
580→
581→  // 2. Return task to in_progress
582→  if (session.task_id) {
583→    await input.surreal.update(session.task_id).merge({
584→      status: "in_progress",
585→      updated_at: new Date(),
586→    });
587→  }
588→
589→  return {
590→    ok: true,
591→    value: {
592→      rejected: true,
593→      continuing: true,
594→    },
595→  };
596→}
