  1→/**
  2→ * Orchestrator Acceptance Test Kit
  3→ *
  4→ * Extends the smoke-test-kit with orchestrator-specific helpers.
  5→ * Boots a Brain server + SurrealDB with isolated namespace.
  6→ * Provides helpers for workspace/task/session setup and OpenCode SDK mocking.
  7→ */
  8→import { afterAll, beforeAll } from "bun:test";
  9→import { readFileSync } from "node:fs";
 10→import { join } from "node:path";
 11→import { RecordId, Surreal } from "surrealdb";
 12→
 13→// ---------------------------------------------------------------------------
 14→// Types
 15→// ---------------------------------------------------------------------------
 16→
 17→export type OrchestratorTestRuntime = {
 18→  baseUrl: string;
 19→  surreal: Surreal;
 20→  namespace: string;
 21→  database: string;
 22→  port: number;
 23→};
 24→
 25→export type TestUser = {
 26→  headers: Record<string, string>;
 27→};
 28→
