268→async function resolveWorkspaceBootstrapConversation(
269→  deps: ServerDependencies,
270→  workspaceRecord: RecordId<"workspace", string>,
271→): Promise<RecordId<"conversation", string>> {
272→  const [onboardingRows] = await deps.surreal
273→    .query<[Array<{ id: RecordId<"conversation", string> }>]>(
274→      "SELECT id, createdAt FROM conversation WHERE workspace = $workspace AND source = 'onboarding' ORDER BY createdAt ASC LIMIT 1;",
275→      {
276→        workspace: workspaceRecord,
277→      },
278→    )
279→    .collect<[Array<{ id: RecordId<"conversation", string> }>]>();
280→
281→  if (onboardingRows.length > 0) {
282→    return onboardingRows[0].id;
283→  }
284→
285→  const [latestRows] = await deps.surreal
286→    .query<[Array<{ id: RecordId<"conversation", string> }>]>(
287→      "SELECT id, createdAt FROM conversation WHERE workspace = $workspace ORDER BY createdAt DESC LIMIT 1;",
288→      {
289→        workspace: workspaceRecord,
290→      },
291→    )
292→    .collect<[Array<{ id: RecordId<"conversation", string> }>]>();
293→
294→  if (latestRows.length > 0) {
295→    return latestRows[0].id;
296→  }
297→
298→  const now = new Date();
299→  const conversationRecord = new RecordId("conversation", randomUUID());
300→  await deps.surreal.create(conversationRecord).content({
301→    createdAt: now,
302→    updatedAt: now,
303→    workspace: workspaceRecord,
304→    source: "onboarding",
305→  });
306→  return conversationRecord;
307→}
