309→async function loadWorkspaceSeeds(
310→  deps: ServerDependencies,
311→  workspaceRecord: RecordId<"workspace", string>,
312→  limit: number,
313→): Promise<OnboardingSeedItem[]> {
314→  const [edgeRows] = await deps.surreal
315→    .query<[ProvenanceEdgeRow[]]>(
316→      [
317→        "SELECT id, `in`, out, confidence, extracted_at",
318→        "FROM extraction_relation",
319→        "WHERE `in` IN array::concat(",
320→        "  (SELECT VALUE id FROM message WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)),",
321→        "  (SELECT VALUE id FROM document_chunk WHERE workspace = $workspace)",
322→        ")",
323→        "ORDER BY extracted_at DESC",
324→        "LIMIT $limit;",
325→      ].join(" "),
326→      {
327→        workspace: workspaceRecord,
328→        limit,
329→      },
330→    )
331→    .collect<[ProvenanceEdgeRow[]]>();
332→
333→  const items: OnboardingSeedItem[] = [];
334→
335→  for (const edge of edgeRows) {
336→    const entityText = await readEntityText(deps.surreal, edge.out);
337→    if (!entityText) {
338→      continue;
339→    }
340→
341→    const sourceTable = edge.in.table.name;
342→    const entityTable = edge.out.table.name;
343→    const sourceKind = (sourceTable === "document_chunk" ? "document_chunk" : "message") as SourceKind;
344→    const sourceLabel = await readSourceLabel(deps, edge.in);
345→
346→    items.push({
347→      id: edge.out.id as string,
348→      kind: entityTable as EntityKind,
349→      text: entityText,
350→      confidence: edge.confidence,
351→      sourceKind,
352→      sourceId: edge.in.id as string,
353→      ...(sourceLabel ? { sourceLabel } : {}),
354→    });
355→  }
356→
357→  return items;
358→}
359→
360→async function readSourceLabel(deps: ServerDependencies, sourceRecord: SourceRecord): Promise<string | undefined> {
361→  const sourceTable = sourceRecord.table.name;
362→  if (sourceTable === "message") {
363→    const row = await deps.surreal.select<{ text: string }>(sourceRecord);
364→    if (!row) {
365→      return undefined;
366→    }
367→    return row.text.slice(0, 140);
368→  }
369→
370→  const chunk = await deps.surreal.select<{
371→    section_heading?: string;
372→    document: RecordId<"document", string>;
373→  }>(sourceRecord);
374→
375→  if (!chunk) {
376→    return undefined;
377→  }
378→
379→  const document = await deps.surreal.select<{ name: string }>(chunk.document);
380→  if (!document) {
381→    return chunk.section_heading;
382→  }
383→
384→  if (chunk.section_heading) {
385→    return `${document.name} · ${chunk.section_heading}`;
386→  }
387→
388→  return document.name;
389→}
