459→      ...(row.subagent_traces && row.subagent_traces.length > 0 ? { subagentTraces: row.subagent_traces } : {}),
460→    } satisfies WorkspaceBootstrapMessage));
461→
462→    let discussEntity: DiscussEntitySummary | undefined;
