517→  request: Request,
518→  shellExec?: ShellExec,
519→): Promise<Response> {
520→  const startedAt = performance.now();
521→  logInfo("workspace.repo_path.update.started", "Repo path update started", { workspaceId });
522→
523→  try {
524→    let body: unknown;
525→    try {
526→      body = await request.json();
527→    } catch {
528→      return jsonError("Request body must be valid JSON", 400);
529→    }
530→
531→    if (!body || typeof body !== "object") {
532→      return jsonError("Body must be an object", 400);
533→    }
534→
535→    const { path } = body as { path?: string };
536→    if (!path || typeof path !== "string" || path.trim().length === 0) {
537→      return jsonError("path is required", 400);
538→    }
539→
540→    if (!shellExec) {
541→      return jsonError("shell execution not available", 500);
542→    }
543→
544→    const repoValidation = await validateRepoPath(path.trim(), shellExec);
545→    if (!repoValidation.ok) {
546→      return jsonError(repoValidation.error, 400);
547→    }
548→
549→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
550→
551→    await deps.surreal.query(
552→      "UPDATE $workspace SET repo_path = $repoPath, updated_at = time::now();",
553→      { workspace: workspaceRecord, repoPath: path.trim() },
554→    );
555→
556→    logInfo("workspace.repo_path.update.completed", "Repo path update completed", {
557→      workspaceId,
558→      repoPath: path.trim(),
559→      durationMs: elapsedMs(startedAt),
560→    });
561→
562→    return jsonResponse({ ok: true }, 200);
563→  } catch (error) {
564→    if (error instanceof HttpError) {
565→      logWarn("workspace.repo_path.update.http_error", "Repo path update failed with client-facing error", {
566→        workspaceId,
567→        statusCode: error.status,
568→      });
569→      return jsonError(error.message, error.status);
570→    }
571→
572→    logError("workspace.repo_path.update.failed", "Repo path update failed", error, { workspaceId });
573→    const errorText = error instanceof Error ? error.message : "repo path update failed";
574→    return jsonError(errorText, 500);
575→  }
576→}
