  1→import { RecordId, type Surreal } from "surrealdb";
  2→import type { OpencodeConfig } from "./config-builder";
  3→import { buildOpencodeConfig } from "./config-builder";
  4→import type { ShellExec } from "./worktree-manager";
  5→import { createWorktree, removeWorktree } from "./worktree-manager";
  6→import type { AssignmentResult } from "./assignment-guard";
  7→import type { AssignmentError, OrchestratorStatus } from "./types";
  8→
  9→// ---------------------------------------------------------------------------
 10→// Types — exported for tests
 11→// ---------------------------------------------------------------------------
 12→
 13→export type OpenCodeHandle = {
 14→  sessionId: string;
 15→  abort: () => void;
 16→};
 17→
 18→export type SessionDeps = {
 19→  surreal: Surreal;
 20→  shellExec: ShellExec;
 21→  brainBaseUrl: string;
 22→  spawnOpenCode?: (
 23→    config: OpencodeConfig,
 24→    worktreePath: string,
 25→  ) => Promise<OpenCodeHandle>;
 26→};
 27→
 28→export type SessionErrorCode =
 29→  | "TASK_NOT_FOUND"
 30→  | "TASK_NOT_ASSIGNABLE"
 31→  | "AGENT_ALREADY_ACTIVE"
 32→  | "WORKSPACE_MISMATCH"
 33→  | "MISSING_TASK_ID"
 34→  | "WORKTREE_ERROR"
 35→  | "SESSION_NOT_FOUND"
 36→  | "SESSION_ERROR";
 37→
 38→export type SessionError = {
 39→  code: SessionErrorCode;
 40→  message: string;
 41→  httpStatus: number;
 42→};
 43→
 44→export type SessionResult<T> =
 45→  | { ok: true; value: T }
 46→  | { ok: false; error: SessionError };
 47→
 48→export type OrchestratorSessionResult = SessionResult<{
 49→  agentSessionId: string;
 50→  streamId: string;
 51→  worktreeBranch: string;
 52→}>;
 53→
 54→export type SessionStatusResult = SessionResult<{
 55→  orchestratorStatus: OrchestratorStatus;
 56→  worktreeBranch?: string;
 57→  worktreePath?: string;
 58→  lastEventAt?: string;
 59→  startedAt?: string;
 60→  error?: string;
 61→}>;
 62→
 63→export type AbortSessionResult = SessionResult<{
 64→  aborted: boolean;
 65→  sessionId: string;
 66→}>;
 67→
 68→export type AcceptSessionResult = SessionResult<{
 69→  accepted: boolean;
 70→  sessionId: string;
 71→}>;
 72→
 73→export type ReviewResult = SessionResult<{
 74→  taskTitle: string;
 75→  diff: import("./worktree-manager").DiffResult;
 76→  session: {
 77→    orchestratorStatus: string;
 78→    worktreeBranch?: string;
 79→    startedAt?: string;
 80→    lastEventAt?: string;
 81→    toolCallCount?: number;
 82→    filesEdited?: number;
 83→  };
 84→}>;
 85→
 86→export type RejectSessionResult = SessionResult<{
 87→  rejected: boolean;
 88→  continuing: boolean;
 89→}>;
 90→
 91→// ---------------------------------------------------------------------------
 92→// In-memory handle registry — maps agentSessionId to OpenCodeHandle
 93→// ---------------------------------------------------------------------------
 94→
 95→const handleRegistry = new Map<string, OpenCodeHandle>();
 96→
 97→// Exported for testing cleanup
 98→export function clearHandleRegistry(): void {
 99→  handleRegistry.clear();
100→}
101→
102→// ---------------------------------------------------------------------------
103→// Pure helpers
104→// ---------------------------------------------------------------------------
105→
106→function sessionNotFound(sessionId: string): SessionError {
107→  return {
108→    code: "SESSION_NOT_FOUND",
109→    message: `Session not found: ${sessionId}`,
110→    httpStatus: 404,
111→  };
112→}
113→
114→function worktreeError(message: string): SessionError {
115→  return {
116→    code: "WORKTREE_ERROR",
117→    message,
118→    httpStatus: 500,
119→  };
120→}
121→
122→function fromAssignmentError(error: AssignmentError): SessionError {
123→  return {
124→    code: error.code as SessionErrorCode,
125→    message: error.message,
126→    httpStatus: error.httpStatus,
127→  };
128→}
129→
130→type SessionLookup =
131→  | { ok: true; session: SessionRow; record: RecordId<"agent_session", string>; status: OrchestratorStatus }
132→  | { ok: false; error: SessionError };
133→
134→async function lookupSession(
135→  surreal: Surreal,
136→  sessionId: string,
137→): Promise<SessionLookup> {
138→  const record = new RecordId("agent_session", sessionId);
139→  const session = await surreal.select<SessionRow>(record);
140→  if (!session) {
141→    return { ok: false, error: sessionNotFound(sessionId) };
142→  }
143→  if (!session.orchestrator_status) {
144→    throw new Error(`agent_session ${sessionId} missing orchestrator_status — data corruption`);
145→  }
146→  const status = session.orchestrator_status as OrchestratorStatus;
147→  return { ok: true, session, record, status };
148→}
149→
150→function generateStreamId(sessionId: string): string {
151→  return `stream-${sessionId}`;
152→}
153→
154→function slugFromTitle(title: string): string {
155→  return title
156→    .toLowerCase()
157→    .replace(/[^a-z0-9]+/g, "-")
158→    .replace(/^-|-$/g, "")
159→    .slice(0, 50);
160→}
161→
162→// ---------------------------------------------------------------------------
163→// Session row shape (DB query result)
164→// ---------------------------------------------------------------------------
165→
166→type SessionRow = {
167→  id: RecordId<"agent_session", string>;
168→  orchestrator_status?: string;
169→  worktree_branch?: string;
170→  worktree_path?: string;
171→  started_at?: string;
172→  last_event_at?: string;
173→  task_id?: RecordId<"task", string>;
174→  workspace?: RecordId<"workspace", string>;
175→  error?: string;
176→};
177→
178→// ---------------------------------------------------------------------------
179→// createOrchestratorSession
180→// ---------------------------------------------------------------------------
181→
182→type CreateSessionInput = {
183→  surreal: Surreal;
184→  shellExec: ShellExec;
185→  brainBaseUrl: string;
186→  workspaceId: string;
187→  taskId: string;
188→  authToken: string;
189→  spawnOpenCode?: (
190→    config: OpencodeConfig,
191→    worktreePath: string,
192→  ) => Promise<OpenCodeHandle>;
193→  validateAssignment: (
194→    surreal: Surreal,
195→    workspaceId: string,
196→    taskId: string,
197→  ) => Promise<AssignmentResult>;
198→  createAgentSession: (input: {
199→    surreal: Surreal;
200→    agent: string;
201→    workspaceRecord: RecordId<"workspace", string>;
202→    taskId?: string;
203→  }) => Promise<{ session_id: string }>;
204→};
205→
206→export async function createOrchestratorSession(
207→  input: CreateSessionInput,
208→): Promise<OrchestratorSessionResult> {
209→  // 1. Validate assignment eligibility
210→  const assignmentResult = await input.validateAssignment(
211→    input.surreal,
212→    input.workspaceId,
213→    input.taskId,
214→  );
215→
216→  if (!assignmentResult.ok) {
217→    return { ok: false, error: fromAssignmentError(assignmentResult.error) };
218→  }
219→
220→  const { validation } = assignmentResult;
221→  const taskSlug = slugFromTitle(validation.title);
222→  const repoRoot = validation.repoPath;
223→
224→  // 2. Create worktree
225→  const worktreeResult = await createWorktree(
226→    input.shellExec,
227→    repoRoot,
228→    taskSlug,
229→  );
230→
231→  if (!worktreeResult.ok) {
232→    return {
233→      ok: false,
234→      error: worktreeError(worktreeResult.error.message),
235→    };
236→  }
237→
238→  const { branchName, worktreePath } = worktreeResult.value;
239→
240→  // 3. Create agent_session record
241→  const { session_id: agentSessionId } = await input.createAgentSession({
242→    surreal: input.surreal,
243→    agent: "opencode",
244→    workspaceRecord: validation.workspaceRecord,
245→    taskId: input.taskId,
246→  });
247→
248→  const streamId = generateStreamId(agentSessionId);
249→
250→  // 4. Build config and spawn OpenCode
251→  const config = buildOpencodeConfig({
252→    brainBaseUrl: input.brainBaseUrl,
253→    workspaceId: input.workspaceId,
254→    authToken: input.authToken,
255→  });
256→
257→  const spawnFn = input.spawnOpenCode ?? defaultSpawnOpenCode;
258→  let handle: OpenCodeHandle;
259→  try {
260→    handle = await spawnFn(config, worktreePath);
261→  } catch (err) {
262→    // Rollback: remove worktree and delete agent_session on spawn failure
263→    await removeWorktree(input.shellExec, repoRoot, branchName);
264→    const sessionRecord = new RecordId("agent_session", agentSessionId);
265→    await input.surreal.delete(sessionRecord);
266→    return {
267→      ok: false,
268→      error: worktreeError(`Failed to spawn OpenCode: ${err instanceof Error ? err.message : String(err)}`),
269→    };
270→  }
271→
272→  // 5. Register handle for later abort
273→  handleRegistry.set(agentSessionId, handle);
274→
275→  // 6. Update agent_session with orchestrator fields
276→  const sessionRecord = new RecordId("agent_session", agentSessionId);
277→  await input.surreal.update(sessionRecord).merge({
278→    orchestrator_status: "spawning" as OrchestratorStatus,
279→    worktree_branch: branchName,
280→    worktree_path: worktreePath,
281→    opencode_session_id: handle.sessionId,
282→    stream_id: streamId,
283→  });
284→
285→  return {
286→    ok: true,
287→    value: {
288→      agentSessionId,
289→      streamId,
290→      worktreeBranch: branchName,
291→    },
292→  };
293→}
