497→// ---------------------------------------------------------------------------
498→// getOrchestratorReview
499→// ---------------------------------------------------------------------------
500→
501→type GetReviewInput = {
502→  surreal: Surreal;
503→  sessionId: string;
504→  getDiff: (repoRoot: string, branchName: string) => Promise<import("./worktree-manager").WorktreeResult<import("./worktree-manager").DiffResult>>;
505→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
506→  getTaskTitle: (taskId: string) => Promise<string>;
507→};
508→
509→export async function getOrchestratorReview(
510→  input: GetReviewInput,
511→): Promise<ReviewResult> {
512→  const lookup = await lookupSession(input.surreal, input.sessionId);
513→  if (!lookup.ok) {
514→    return { ok: false, error: lookup.error };
515→  }
516→  const { session, status } = lookup;
517→
518→  if (status === "aborted") {
519→    return { ok: false, error: sessionAborted(input.sessionId) };
520→  }
521→
522→  if (!REVIEWABLE_STATUSES.includes(status)) {
523→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "review") };
524→  }
525→
526→  // Get diff from the branch
527→  const branchName = session.worktree_branch ?? "";
528→  if (!session.workspace) {
529→    throw new Error(`agent_session ${input.sessionId} missing workspace — data corruption`);
530→  }
531→  const repoRoot = await input.resolveRepoRoot(session.workspace as RecordId<"workspace", string>);
532→  const diffResult = await input.getDiff(repoRoot, branchName);
533→
534→  const diff = diffResult.ok
535→    ? diffResult.value
536→    : { files: [], rawDiff: "", stats: { filesChanged: 0, insertions: 0, deletions: 0 } };
537→
538→  // Get task title
539→  const taskId = session.task_id ? (session.task_id.id as string) : "";
540→  const taskTitle = taskId ? await input.getTaskTitle(taskId) : "";
541→
542→  return {
543→    ok: true,
544→    value: {
545→      taskTitle,
546→      diff,
547→      session: {
548→        orchestratorStatus: status,
549→        ...(session.worktree_branch ? { worktreeBranch: session.worktree_branch } : {}),
550→        ...(session.started_at ? { startedAt: session.started_at } : {}),
551→        ...(session.last_event_at ? { lastEventAt: session.last_event_at } : {}),
552→      },
553→    },
554→  };
555→}
