  1→import { FormEvent, useEffect, useState } from "react";
  2→import type { UIMessage } from "ai";
  3→import type {
  4→  CreateWorkspaceRequest,
  5→  CreateWorkspaceResponse,
  6→  WorkspaceBootstrapMessage,
  7→  WorkspaceBootstrapResponse,
  8→} from "../../shared/contracts";
  9→import { useWorkspaceState, type BootstrapPayload } from "../stores/workspace-state";
 10→
 11→const ACTIVE_WORKSPACE_STORAGE_KEY = "brain.activeWorkspaceId";
 12→
 13→type UseWorkspaceReturn = {
 14→  isReady: boolean;
 15→  isBootstrapping: boolean;
 16→  isCreatingWorkspace: boolean;
 17→  errorMessage?: string;
 18→  createWorkspaceName: string;
 19→  createWorkspaceDescription: string;
 20→  createWorkspaceRepoPath: string;
 21→  canCreateWorkspace: boolean;
 22→  setCreateWorkspaceName: (name: string) => void;
 23→  setCreateWorkspaceDescription: (description: string) => void;
 24→  setCreateWorkspaceRepoPath: (path: string) => void;
 25→  onCreateWorkspace: (event: FormEvent<HTMLFormElement>) => void;
 26→};
 27→
 28→function bootstrapMessagesToUIMessages(messages: WorkspaceBootstrapMessage[]): UIMessage[] {
 29→  return messages.map((m) => ({
 30→    id: m.id,
 31→    role: m.role,
 32→    parts: [{ type: "text" as const, text: m.text }],
 33→    createdAt: new Date(m.createdAt),
 34→  }));
 35→}
 36→
 37→function parseBootstrapMessages(payload: WorkspaceBootstrapResponse): BootstrapPayload {
 38→  return { messages: bootstrapMessagesToUIMessages(payload.messages) };
 39→}
 40→
 41→export { parseBootstrapMessages, ACTIVE_WORKSPACE_STORAGE_KEY };
 42→
 43→export function useWorkspace(): UseWorkspaceReturn {
 44→  const store = useWorkspaceState();
 45→  const [createWorkspaceName, setCreateWorkspaceName] = useState("");
 46→  const [createWorkspaceDescription, setCreateWorkspaceDescription] = useState("");
 47→  const [createWorkspaceRepoPath, setCreateWorkspaceRepoPath] = useState("");
 48→  const [isCreatingWorkspace, setIsCreatingWorkspace] = useState(false);
 49→  const [errorMessage, setErrorMessage] = useState<string | undefined>();
 50→
 51→  const canCreateWorkspace = createWorkspaceName.trim().length > 0;
 52→
 53→  useEffect(() => {
 54→    const existingWorkspaceId = window.localStorage.getItem(ACTIVE_WORKSPACE_STORAGE_KEY);
 55→    if (!existingWorkspaceId) {
 56→      return;
 57→    }
 58→
 59→    void bootstrapWorkspace(existingWorkspaceId);
 60→  }, []);
 61→
 62→  async function bootstrapWorkspace(workspaceId: string) {
 63→    store.setIsBootstrapping(true);
 64→    setErrorMessage(undefined);
 65→
 66→    let response: Response;
 67→    try {
 68→      response = await fetch(`/api/workspaces/${encodeURIComponent(workspaceId)}/bootstrap`);
 69→    } catch (error) {
 70→      const messageText = error instanceof Error ? error.message : "Network error";
 71→      setErrorMessage(messageText);
 72→      store.setIsBootstrapping(false);
 73→      return;
 74→    }
 75→
 76→    if (!response.ok) {
 77→      if (response.status === 404) {
 78→        window.localStorage.removeItem(ACTIVE_WORKSPACE_STORAGE_KEY);
 79→        store.clearWorkspace();
 80→      }
 81→      const body = await response.text();
 82→      setErrorMessage(body);
 83→      store.setIsBootstrapping(false);
 84→      return;
 85→    }
 86→
 87→    const payload = (await response.json()) as WorkspaceBootstrapResponse;
 88→    applyBootstrapPayload(payload);
 89→    store.setIsBootstrapping(false);
 90→  }
 91→
 92→  function applyBootstrapPayload(payload: WorkspaceBootstrapResponse) {
 93→    const parsed = parseBootstrapMessages(payload);
 94→
 95→    store.setSeedItems(payload.seeds);
 96→    store.setSidebar(payload.sidebar);
 97→    store.setBootstrapPayload(parsed);
 98→    store.applyWorkspace({
 99→      id: payload.workspaceId,
100→      name: payload.workspaceName,
101→      repoPath: payload.repoPath,
102→      onboardingComplete: payload.onboardingComplete,
103→      onboardingState: payload.onboardingState,
104→      conversationId: payload.conversationId,
105→    });
106→  }
107→
108→  async function onCreateWorkspace(event: FormEvent<HTMLFormElement>) {
109→    event.preventDefault();
110→
111→    const name = createWorkspaceName.trim();
112→    if (isCreatingWorkspace) {
113→      return;
114→    }
115→
116→    if (!name) {
117→      setErrorMessage("Workspace name is required");
118→      return;
119→    }
120→
121→    setErrorMessage(undefined);
122→    setIsCreatingWorkspace(true);
123→
124→    const description = createWorkspaceDescription.trim();
125→    const repoPath = createWorkspaceRepoPath.trim();
126→    const requestBody: CreateWorkspaceRequest = {
127→      name,
128→      ...(description.length > 0 ? { description } : {}),
129→      ...(repoPath.length > 0 ? { repoPath } : {}),
130→    };
131→
132→    try {
133→      const response = await fetch("/api/workspaces", {
134→        method: "POST",
135→        headers: {
136→          "Content-Type": "application/json",
137→        },
138→        body: JSON.stringify(requestBody),
139→      });
140→
141→      if (!response.ok) {
142→        const body = await response.text();
143→        setErrorMessage(body);
144→        return;
145→      }
146→
147→      const payload = (await response.json()) as Partial<CreateWorkspaceResponse>;
148→      if (typeof payload.workspaceId !== "string" || payload.workspaceId.trim().length === 0) {
149→        throw new Error("create workspace response is missing workspaceId");
150→      }
151→
152→      window.localStorage.setItem(ACTIVE_WORKSPACE_STORAGE_KEY, payload.workspaceId);
153→      await bootstrapWorkspace(payload.workspaceId);
154→      setCreateWorkspaceName("");
155→      setCreateWorkspaceDescription("");
156→      setCreateWorkspaceRepoPath("");
157→    } catch (error) {
158→      const messageText = error instanceof Error ? error.message : "Workspace creation failed";
159→      setErrorMessage(messageText);
160→    } finally {
161→      setIsCreatingWorkspace(false);
162→    }
163→  }
164→
165→  return {
166→    isReady: store.workspaceId !== undefined && !store.isBootstrapping,
167→    isBootstrapping: store.isBootstrapping,
168→    isCreatingWorkspace,
169→    errorMessage,
170→    createWorkspaceName,
171→    createWorkspaceDescription,
172→    createWorkspaceRepoPath,
173→    canCreateWorkspace,
174→    setCreateWorkspaceName,
175→    setCreateWorkspaceDescription,
176→    setCreateWorkspaceRepoPath,
177→    onCreateWorkspace,
178→  };
179→}
