 55→export const useWorkspaceState = create<WorkspaceStateStore>((set, get) => ({
 56→  workspaceId: undefined,
 57→  workspaceName: undefined,
 58→  repoPath: undefined,
 59→  onboardingComplete: false,
 60→  onboardingState: undefined,
 61→  conversationId: undefined,
 62→  sidebar: undefined,
 63→  seedItems: [],
 64→  isBootstrapping: false,
 65→  sidebarHandlers: undefined,
 66→  bootstrapPayload: undefined,
 67→
 68→  setWorkspaceId: (workspaceId) => set({ workspaceId }),
 69→  setWorkspaceName: (name) => set({ workspaceName: name }),
 70→  setRepoPath: (repoPath) => set({ repoPath }),
 71→  setOnboardingState: (onboardingState) =>
 72→    set({ onboardingState, onboardingComplete: onboardingState === "complete" }),
 73→  setConversationId: (conversationId) => set({ conversationId }),
 74→  setSidebar: (sidebar) => set({ sidebar }),
 75→  setSeedItems: (seedItems) => set({ seedItems }),
 76→  mergeSeedItems: (items) => {
 77→    const existing = get().seedItems;
 78→    const deduped = new Map(
 79→      existing.map((item) => [`${item.id}:${item.sourceKind}:${item.sourceId}`, item]),
 80→    );
 81→    for (const item of items) {
 82→      const key = `${item.id}:${item.sourceKind}:${item.sourceId}`;
 83→      if (!deduped.has(key)) {
 84→        deduped.set(key, item);
 85→      }
 86→    }
 87→    set({ seedItems: [...deduped.values()] });
 88→  },
 89→  setIsBootstrapping: (isBootstrapping) => set({ isBootstrapping }),
 90→  setSidebarHandlers: (sidebarHandlers) => set({ sidebarHandlers }),
 91→  setBootstrapPayload: (bootstrapPayload) => set({ bootstrapPayload }),
 92→  clearWorkspace: () =>
