 99→      conversationId: undefined,
100→      sidebar: undefined,
101→      seedItems: [],
102→      isBootstrapping: false,
103→      sidebarHandlers: undefined,
104→      bootstrapPayload: undefined,
105→    }),
106→  applyWorkspace: (ws) =>
107→    set({
108→      workspaceId: ws.id,
109→      workspaceName: ws.name,
110→      repoPath: ws.repoPath,
111→      onboardingComplete: ws.onboardingComplete,
112→      onboardingState: ws.onboardingState,
