 16→function AppShell() {
 17→  const workspace = useWorkspace();
 18→  const sidebar = useWorkspaceState((s) => s.sidebar);
 19→  const sidebarHandlers = useWorkspaceState((s) => s.sidebarHandlers);
 20→  const workspaceName = useWorkspaceState((s) => s.workspaceName);
 21→  const onboardingState = useWorkspaceState((s) => s.onboardingState);
 22→  const navigate = useNavigate();
 23→  const [searchOpen, setSearchOpen] = useState(false);
 24→
 25→  function handleNewConversation() {
 26→    if (sidebarHandlers) {
 27→      sidebarHandlers.onNewConversation();
 28→    }
 29→    void navigate({ to: "/chat" });
 30→  }
 31→
 32→  function handleSelectConversation(conversationId: string) {
 33→    if (sidebarHandlers) {
 34→      sidebarHandlers.onSelectConversation(conversationId);
 35→    }
 36→    void navigate({ to: "/chat/$conversationId", params: { conversationId } });
 37→  }
 38→
 39→  return (
 40→    <WorkspaceGuard
 41→      isReady={workspace.isReady}
 42→      isBootstrapping={workspace.isBootstrapping}
 43→      isCreatingWorkspace={workspace.isCreatingWorkspace}
 44→      canCreateWorkspace={workspace.canCreateWorkspace}
 45→      createWorkspaceName={workspace.createWorkspaceName}
 46→      createWorkspaceDescription={workspace.createWorkspaceDescription}
 47→      createWorkspaceRepoPath={workspace.createWorkspaceRepoPath}
 48→      errorMessage={workspace.errorMessage}
 49→      setCreateWorkspaceName={workspace.setCreateWorkspaceName}
 50→      setCreateWorkspaceDescription={workspace.setCreateWorkspaceDescription}
 51→      setCreateWorkspaceRepoPath={workspace.setCreateWorkspaceRepoPath}
 52→      onCreateWorkspace={workspace.onCreateWorkspace}
 53→    >
 54→      <div className="app-shell">
 55→        <WorkspaceSidebar
 56→          sidebar={sidebar}
 57→          activeConversationId={sidebarHandlers?.activeConversationId}
 58→          isLoading={sidebarHandlers?.isLoading ?? false}
 59→          onNewConversation={handleNewConversation}
 60→          onSelectConversation={handleSelectConversation}
 61→        />
 62→        <div className="app-main">
 63→          <div className="content-header">
 64→            <span className="content-header-title">{workspaceName}</span>
 65→            {onboardingState === "active" ? (
 66→              <span className="onboarding-badge">Setting up</span>
