 88→// Root route: bare outlet for public/authenticated split
 89→const rootRoute = createRootRoute({
 90→  component: () => <Outlet />,
 91→});
 92→
 93→// Public routes (no auth required)
 94→const signInRoute = createRoute({
 95→  getParentRoute: () => rootRoute,
 96→  path: "/sign-in",
 97→  component: SignInPage,
 98→});
 99→
100→const consentRoute = createRoute({
101→  getParentRoute: () => rootRoute,
102→  path: "/consent",
103→  component: ConsentPage,
104→});
105→
106→// Authenticated layout — checks session before rendering
107→const authLayout = createRoute({
108→  getParentRoute: () => rootRoute,
109→  id: "authenticated",
110→  component: AppShell,
111→  beforeLoad: async ({ location }) => {
112→    const { data } = await authClient.getSession();
113→    if (!data) {
114→      throw redirect({
115→        to: "/sign-in",
116→        search: { redirectTo: location.href },
117→      });
118→    }
119→  },
120→});
121→
122→const homeRoute = createRoute({
123→  getParentRoute: () => authLayout,
124→  path: "/",
125→  component: HomePage,
126→});
127→
128→type ChatSearch = { message?: string };
129→
130→const validateChatSearch = (search: Record<string, unknown>): ChatSearch => ({
131→  ...(typeof search.message === "string" ? { message: search.message } : {}),
132→});
133→
134→const chatRoute = createRoute({
135→  getParentRoute: () => authLayout,
136→  path: "/chat",
137→  component: ChatPage,
138→  validateSearch: validateChatSearch,
139→});
140→
141→const chatConversationRoute = createRoute({
142→  getParentRoute: () => authLayout,
143→  path: "/chat/$conversationId",
144→  component: ChatPage,
145→  validateSearch: validateChatSearch,
146→});
147→
148→const graphRoute = createRoute({
149→  getParentRoute: () => authLayout,
150→  path: "/graph",
151→  component: GraphPage,
152→});
153→
154→const reviewRoute = createRoute({
155→  getParentRoute: () => authLayout,
156→  path: "/review/$sessionId",
157→  component: ReviewPage,
158→});
159→
160→const routeTree = rootRoute.addChildren([
161→  signInRoute,
162→  consentRoute,
163→  authLayout.addChildren([homeRoute, chatRoute, chatConversationRoute, graphRoute, reviewRoute]),
164→]);
165→
166→export const router = createRouter({ routeTree });
167→
168→declare module "@tanstack/react-router" {
169→  interface Register {
170→    router: typeof router;
171→  }
172→}
