 3→// ---------------------------------------------------------------------------
 4→// Port: shell execution dependency (injected, not imported)
 5→// ---------------------------------------------------------------------------
 6→
 7→type ShellExec = (
 8→  command: string,
 9→  args: string[],
10→  cwd: string,
11→) => Promise<ShellExecResult>;
12→
13→// ---------------------------------------------------------------------------
14→// Result type
15→// ---------------------------------------------------------------------------
16→
17→export type RepoPathValidation =
18→  | { ok: true }
19→  | { ok: false; error: string };
20→
21→// ---------------------------------------------------------------------------
22→// validateRepoPath — pure function with injected shell exec
23→// ---------------------------------------------------------------------------
24→
25→export async function validateRepoPath(
26→  path: string,
27→  shellExec: ShellExec,
28→): Promise<RepoPathValidation> {
29→  try {
30→    const result = await shellExec(
31→      "git",
32→      ["-C", path, "rev-parse", "--git-dir"],
33→      path,
34→    );
35→
36→    if (result.exitCode === 0) {
37→      return { ok: true };
38→    }
39→
40→    return { ok: false, error: `${path} is not a valid git repository` };
41→  } catch {
42→    return { ok: false, error: `path does not exist or is not accessible: ${path}` };
43→  }
44→}
