 84→  return {
 85→    ok: false,
 86→    error: {
 87→      code: "REPO_PATH_REQUIRED",
 88→      message: `Workspace ${workspaceId} has no repo_path configured. Set a repository path before assigning tasks to agents.`,
 89→      httpStatus: 400,
 90→    },
 91→  };
 92→}
