 94→// ---------------------------------------------------------------------------
 95→// DB queries (thin wrappers — side effects isolated here)
 96→// ---------------------------------------------------------------------------
 97→
 98→async function fetchTask(
 99→  surreal: Surreal,
100→  taskRecord: RecordId<"task", string>,
101→): Promise<TaskRow | undefined> {
102→  const [rows] = await surreal.query<[TaskRow[]]>(
103→    `SELECT id, title, status, workspace FROM $taskRecord;`,
104→    { taskRecord },
105→  );
106→  return rows[0];
107→}
108→
109→type WorkspaceRepoRow = {
110→  repo_path?: string;
111→};
112→
113→async function fetchWorkspaceRepoPath(
114→  surreal: Surreal,
115→  workspaceRecord: RecordId<"workspace", string>,
116→): Promise<string | undefined> {
117→  const [rows] = await surreal.query<[WorkspaceRepoRow[]]>(
118→    `SELECT repo_path FROM $workspaceRecord;`,
119→    { workspaceRecord },
120→  );
121→  return rows[0]?.repo_path;
122→}
123→
124→async function hasActiveSession(
125→  surreal: Surreal,
126→  taskRecord: RecordId<"task", string>,
127→): Promise<boolean> {
128→  const [rows] = await surreal.query<[ActiveSessionRow[]]>(
129→    `SELECT id, orchestrator_status FROM agent_session
130→     WHERE task_id = $taskRecord
131→       AND orchestrator_status IN $activeStatuses
132→     LIMIT 1;`,
133→    { taskRecord, activeStatuses: [...ACTIVE_ORCHESTRATOR_STATUSES] },
134→  );
135→  return rows.length > 0;
136→}
