 25→
 26→type QueryResult = Array<Record<string, unknown>>;
 27→
 28→/** Tracks calls made to the surreal stub for spy assertions */
 29→type SurrealSpy = {
 30→  stub: unknown;
 31→  queries: Array<{ sql: string; bindings?: Record<string, unknown> }>;
 32→  creates: Array<{ record: unknown; content: unknown }>;
 33→  updates: Array<{ record: unknown; merge: unknown }>;
 34→  selects: Array<{ record: unknown }>;
 35→};
 36→
 37→function createSurrealSpy(responses: {
 38→  taskQuery?: QueryResult;
 39→  sessionQuery?: QueryResult;
 40→  sessionSelect?: Record<string, unknown>;
 41→  createReturn?: Record<string, unknown>;
 42→}): SurrealSpy {
 43→  const spy: SurrealSpy = {
 44→    stub: undefined,
 45→    queries: [],
 46→    creates: [],
 47→    updates: [],
 48→    selects: [],
 49→  };
 50→
 51→  spy.stub = {
 52→    query(sql: string, bindings?: Record<string, unknown>) {
 53→      spy.queries.push({ sql, bindings });
 54→
 55→      // Task lookup
 56→      if (sql.includes("FROM $taskRecord")) {
 57→        return Promise.resolve([responses.taskQuery ?? []]);
 58→      }
 59→      // Active session check
 60→      if (sql.includes("orchestrator_status") && sql.includes("agent_session")) {
 61→        return Promise.resolve([responses.sessionQuery ?? []]);
 62→      }
 63→      // Session orchestrator fields query (for getStatus)
 64→      if (sql.includes("orchestrator_status") && sql.includes("$sessionRecord")) {
 65→        return Promise.resolve([responses.sessionSelect ? [responses.sessionSelect] : []]);
 66→      }
 67→      // Update queries
 68→      if (sql.includes("UPDATE")) {
 69→        return Promise.resolve([responses.createReturn ?? {}]);
 70→      }
 71→      return Promise.resolve([[]]);
 72→    },
 73→    create(record: unknown) {
 74→      return {
 75→        content(content: unknown) {
 76→          spy.creates.push({ record, content });
 77→          return Promise.resolve(responses.createReturn ?? { id: record });
 78→        },
 79→      };
 80→    },
 81→    update(record: unknown) {
 82→      return {
 83→        merge(data: unknown) {
 84→          spy.updates.push({ record, merge: data });
 85→          return Promise.resolve({ id: record, ...data as object });
 86→        },
 87→      };
 88→    },
 89→    select(record: unknown) {
 90→      spy.selects.push({ record });
 91→      return Promise.resolve(responses.sessionSelect ?? undefined);
 92→    },
 93→  };
 94→
 95→  return spy;
 96→}
