  1→/**
  2→ * Orchestrator HTTP route handlers.
  3→ *
  4→ * Pure request->response mappings that delegate to session-lifecycle functions
  5→ * injected via OrchestratorRouteDeps. No direct DB or IO access.
  6→ */
  7→import { jsonError, jsonResponse } from "../http/response";
  8→import { withRequestLogging, type RouteHandler } from "../http/request-logging";
  9→import type {
 10→  OrchestratorSessionResult,
 11→  SessionStatusResult,
 12→  AbortSessionResult,
 13→  AcceptSessionResult,
 14→  ReviewResult,
 15→  RejectSessionResult,
 16→} from "./session-lifecycle";
 17→import type { SseRegistry } from "../streaming/sse-registry";
 18→
 19→// ---------------------------------------------------------------------------
 20→// Port: Dependencies as function signatures
 21→// ---------------------------------------------------------------------------
 22→
 23→export type OrchestratorRouteDeps = {
 24→  createSession: (
 25→    workspaceId: string,
 26→    taskId: string,
 27→    authToken: string,
 28→  ) => Promise<OrchestratorSessionResult>;
 29→  getSessionStatus: (sessionId: string) => Promise<SessionStatusResult>;
 30→  abortSession: (sessionId: string) => Promise<AbortSessionResult>;
 31→  acceptSession: (
 32→    sessionId: string,
 33→    summary: string,
 34→  ) => Promise<AcceptSessionResult>;
 35→  getReview: (sessionId: string) => Promise<ReviewResult>;
 36→  rejectSession: (
 37→    sessionId: string,
 38→    feedback: string,
 39→  ) => Promise<RejectSessionResult>;
 40→};
 41→
 42→// ---------------------------------------------------------------------------
 43→// Request body parsing
 44→// ---------------------------------------------------------------------------
 45→
 46→type AssignBody = { taskId?: string };
 47→type AcceptBody = { summary?: string };
 48→type RejectBody = { feedback?: string };
 49→
 50→async function parseJsonBody<T>(request: Request): Promise<T | undefined> {
 51→  try {
 52→    return (await request.json()) as T;
 53→  } catch {
 54→    return undefined;
 55→  }
 56→}
 57→
 58→function extractAuthToken(request: Request): string {
 59→  return request.headers.get("Cookie") ?? "";
 60→}
 61→
 62→// ---------------------------------------------------------------------------
 63→// Response builders (pure)
 64→// ---------------------------------------------------------------------------
 65→
 66→function assignResponse(
 67→  workspaceId: string,
 68→  value: { agentSessionId: string; streamId: string; worktreeBranch: string },
 69→): Response {
 70→  return jsonResponse(
 71→    {
 72→      agentSessionId: value.agentSessionId,
 73→      streamId: value.streamId,
 74→      streamUrl: `/api/orchestrator/${workspaceId}/sessions/${value.agentSessionId}/stream`,
 75→    },
 76→    200,
 77→  );
 78→}
 79→
 80→function statusResponse(
 81→  sessionId: string,
 82→  value: {
 83→    orchestratorStatus: string;
 84→    worktreeBranch?: string;
 85→    worktreePath?: string;
 86→    startedAt?: string;
 87→    lastEventAt?: string;
 88→    error?: string;
 89→  },
 90→): Response {
 91→  return jsonResponse(
 92→    {
 93→      agentSessionId: sessionId,
 94→      orchestratorStatus: value.orchestratorStatus,
 95→      ...(value.worktreeBranch ? { worktreeBranch: value.worktreeBranch } : {}),
 96→      ...(value.worktreePath ? { worktreePath: value.worktreePath } : {}),
 97→      ...(value.startedAt ? { startedAt: value.startedAt } : {}),
 98→      ...(value.lastEventAt ? { lastEventAt: value.lastEventAt } : {}),
 99→      ...(value.error ? { error: value.error } : {}),
100→    },
101→    200,
102→  );
103→}
104→
105→function acceptResponse(): Response {
106→  return jsonResponse({ accepted: true, taskStatus: "done" }, 200);
107→}
108→
109→function abortResponse(): Response {
110→  return jsonResponse({ aborted: true, taskStatus: "ready" }, 200);
111→}
112→
113→function reviewResponse(value: {
114→  taskTitle: string;
115→  diff: unknown;
116→  session: unknown;
117→}): Response {
118→  return jsonResponse(value, 200);
119→}
120→
121→function rejectResponse(): Response {
122→  return jsonResponse({ rejected: true, continuing: true }, 200);
123→}
124→
125→function sessionErrorResponse(error: {
126→  message: string;
127→  httpStatus: number;
128→}): Response {
129→  return jsonError(error.message, error.httpStatus);
130→}
131→
132→// ---------------------------------------------------------------------------
133→// Route handler factory
134→// ---------------------------------------------------------------------------
135→
136→export function createOrchestratorRouteHandlers(deps: OrchestratorRouteDeps) {
137→  const assign: RouteHandler = async (request) => {
138→    const workspaceId = request.params.workspaceId;
139→    const body = await parseJsonBody<AssignBody>(request);
140→
141→    if (!body?.taskId) {
142→      return jsonError("taskId is required", 400);
143→    }
144→
145→    const authToken = extractAuthToken(request);
146→    const result = await deps.createSession(workspaceId, body.taskId, authToken);
147→
148→    if (!result.ok) {
149→      return sessionErrorResponse(result.error);
150→    }
151→
152→    return assignResponse(workspaceId, result.value);
153→  };
154→
155→  const status: RouteHandler = async (request) => {
156→    const sessionId = request.params.sessionId;
157→    const result = await deps.getSessionStatus(sessionId);
158→
159→    if (!result.ok) {
160→      return sessionErrorResponse(result.error);
161→    }
162→
163→    return statusResponse(sessionId, result.value);
164→  };
165→
166→  const accept: RouteHandler = async (request) => {
167→    const sessionId = request.params.sessionId;
168→    const body = await parseJsonBody<AcceptBody>(request);
169→    const summary = body?.summary ?? "";
170→
171→    const result = await deps.acceptSession(sessionId, summary);
172→
173→    if (!result.ok) {
174→      return sessionErrorResponse(result.error);
175→    }
176→
177→    return acceptResponse();
178→  };
179→
180→  const abort: RouteHandler = async (request) => {
181→    const sessionId = request.params.sessionId;
182→    const result = await deps.abortSession(sessionId);
183→
184→    if (!result.ok) {
185→      return sessionErrorResponse(result.error);
186→    }
187→
188→    return abortResponse();
189→  };
190→
191→  const review: RouteHandler = async (request) => {
192→    const sessionId = request.params.sessionId;
193→    const result = await deps.getReview(sessionId);
194→
195→    if (!result.ok) {
196→      return sessionErrorResponse(result.error);
197→    }
198→
199→    return reviewResponse(result.value);
200→  };
201→
202→  const reject: RouteHandler = async (request) => {
203→    const sessionId = request.params.sessionId;
204→    const body = await parseJsonBody<RejectBody>(request);
205→
206→    if (!body?.feedback || body.feedback.trim() === "") {
207→      return jsonError("feedback is required", 400);
208→    }
209→
210→    const result = await deps.rejectSession(sessionId, body.feedback);
211→
212→    if (!result.ok) {
213→      return sessionErrorResponse(result.error);
214→    }
215→
216→    return rejectResponse();
217→  };
218→
219→  return { assign, status, accept, abort, review, reject };
220→}
221→
222→// ---------------------------------------------------------------------------
223→// SSE stream route handler factory
224→// ---------------------------------------------------------------------------
225→
226→export type StreamRouteDeps = {
227→  sseRegistry: SseRegistry;
228→};
229→
230→export function createStreamRouteHandler(deps: StreamRouteDeps) {
231→  const stream: RouteHandler = async (request) => {
232→    const streamId = request.params.streamId;
233→
234→    if (!streamId) {
235→      return jsonError("streamId is required", 400);
236→    }
237→
238→    return deps.sseRegistry.handleStreamRequest(streamId);
239→  };
240→
241→  return { stream };
242→}
243→
244→// ---------------------------------------------------------------------------
245→// Wiring factory: creates OrchestratorRouteDeps from server dependencies
246→// ---------------------------------------------------------------------------
247→
248→export type OrchestratorWiringDeps = {
249→  surreal: import("surrealdb").Surreal;
250→  shellExec: import("./worktree-manager").ShellExec;
251→  brainBaseUrl: string;
252→  sseRegistry?: SseRegistry;
253→};
254→
255→export function wireOrchestratorRoutes(
256→  wiringDeps: OrchestratorWiringDeps,
257→): {
258→  assign: RouteHandler;
259→  status: RouteHandler;
260→  accept: RouteHandler;
261→  abort: RouteHandler;
262→  review: RouteHandler;
263→  reject: RouteHandler;
264→  stream?: RouteHandler;
265→} {
266→  // Lazy imports to keep module boundary clean
267→  const lifecycleImport = import("./session-lifecycle");
268→  const queriesImport = import("../mcp/mcp-queries");
269→  const guardImport = import("./assignment-guard");
270→
271→  // Helper: resolve repo_path from workspace record
272→  const resolveRepoRoot = async (workspaceRecord: import("surrealdb").RecordId<"workspace", string>): Promise<string> => {
273→    const [rows] = await wiringDeps.surreal.query<[Array<{ repo_path?: string }>]>(
274→      `SELECT repo_path FROM $ws;`,
275→      { ws: workspaceRecord },
276→    );
277→    const repoPath = rows[0]?.repo_path;
278→    if (!repoPath) {
279→      throw new Error(`Workspace ${workspaceRecord.id} has no repo_path configured`);
280→    }
281→    return repoPath;
282→  };
283→
284→  // Mock OpenCode spawning when env var is set (for acceptance tests)
285→  const mockOpenCode = process.env.ORCHESTRATOR_MOCK_OPENCODE === "true";
286→  const mockSpawnOpenCode = mockOpenCode
287→    ? async () => ({
288→        sessionId: crypto.randomUUID(),
289→        abort: () => {},
290→      })
291→    : undefined;
292→
293→  const routeDeps: OrchestratorRouteDeps = {
294→    createSession: async (workspaceId, taskId, authToken) => {
295→      const [lifecycle, queries, guard] = await Promise.all([
296→        lifecycleImport,
297→        queriesImport,
298→        guardImport,
299→      ]);
300→      return lifecycle.createOrchestratorSession({
301→        surreal: wiringDeps.surreal,
302→        shellExec: wiringDeps.shellExec,
303→        brainBaseUrl: wiringDeps.brainBaseUrl,
304→        workspaceId,
305→        taskId,
306→        authToken,
307→        validateAssignment: guard.validateAssignment,
308→        createAgentSession: queries.createAgentSession,
309→        ...(mockSpawnOpenCode ? { spawnOpenCode: mockSpawnOpenCode } : {}),
310→      });
311→    },
312→
313→    getSessionStatus: async (sessionId) => {
314→      const lifecycle = await lifecycleImport;
315→      return lifecycle.getOrchestratorSessionStatus({
316→        surreal: wiringDeps.surreal,
317→        sessionId,
318→      });
319→    },
320→
321→    abortSession: async (sessionId) => {
322→      const [lifecycle, queries] = await Promise.all([
323→        lifecycleImport,
324→        queriesImport,
325→      ]);
326→      return lifecycle.abortOrchestratorSession({
327→        surreal: wiringDeps.surreal,
328→        shellExec: wiringDeps.shellExec,
329→        resolveRepoRoot,
330→        sessionId,
331→        endAgentSession: queries.endAgentSession,
332→      });
333→    },
334→
335→    acceptSession: async (sessionId, summary) => {
336→      const [lifecycle, queries] = await Promise.all([
337→        lifecycleImport,
338→        queriesImport,
339→      ]);
340→      return lifecycle.acceptOrchestratorSession({
341→        surreal: wiringDeps.surreal,
342→        sessionId,
343→        summary,
344→        endAgentSession: queries.endAgentSession,
345→      });
346→    },
347→
348→    getReview: async (sessionId) => {
349→      const [lifecycle, worktreeManager] = await Promise.all([
350→        lifecycleImport,
351→        import("./worktree-manager"),
352→      ]);
353→      return lifecycle.getOrchestratorReview({
354→        surreal: wiringDeps.surreal,
355→        sessionId,
356→        resolveRepoRoot,
357→        getDiff: (repoRoot: string, branchName: string) =>
358→          worktreeManager.getDiff(wiringDeps.shellExec, repoRoot, branchName),
359→        getTaskTitle: async (taskId: string) => {
360→          const { RecordId } = await import("surrealdb");
361→          const taskRecord = new RecordId("task", taskId);
362→          const rows = (await wiringDeps.surreal.query(
363→            `SELECT title FROM $task;`,
364→            { task: taskRecord },
365→          )) as Array<Array<{ title: string }>>;
366→          return rows[0]?.[0]?.title ?? "";
367→        },
368→      });
369→    },
370→
371→    rejectSession: async (sessionId, feedback) => {
372→      const lifecycle = await lifecycleImport;
373→      return lifecycle.rejectOrchestratorSession({
374→        surreal: wiringDeps.surreal,
375→        sessionId,
376→        feedback,
377→      });
378→    },
379→  };
380→
381→  const handlers = createOrchestratorRouteHandlers(routeDeps);
382→
383→  const streamHandler = wiringDeps.sseRegistry
384→    ? createStreamRouteHandler({ sseRegistry: wiringDeps.sseRegistry })
385→    : undefined;
386→
387→  return {
388→    assign: withRequestLogging("orchestrator.assign", "POST", handlers.assign),
389→    status: withRequestLogging("orchestrator.status", "GET", handlers.status),
390→    accept: withRequestLogging("orchestrator.accept", "POST", handlers.accept),
391→    abort: withRequestLogging("orchestrator.abort", "POST", handlers.abort),
392→    review: withRequestLogging("orchestrator.review", "GET", handlers.review),
393→    reject: withRequestLogging("orchestrator.reject", "POST", handlers.reject),
394→    ...(streamHandler
395→      ? { stream: withRequestLogging("orchestrator.stream", "GET", streamHandler.stream) }
396→      : {}),
397→  };
398→}
