  1→import type { CreateWorkspaceRequest, OnboardingAction } from "../../shared/contracts";
  2→import { HttpError } from "./errors";
  3→
  4→const MAX_UPLOAD_BYTES = 2 * 1024 * 1024;
  5→const allowedUploadExtensions = new Set(["md", "txt"]);
  6→
  7→export type IncomingAttachment = {
  8→  fileName: string;
  9→  mimeType: string;
 10→  sizeBytes: number;
 11→  content: string;
 12→};
 13→
 14→export type ParsedIncomingMessage = {
 15→  clientMessageId: string;
 16→  workspaceId: string;
 17→  conversationId?: string;
 18→  text: string;
 19→  onboardingAction?: OnboardingAction;
 20→  attachment?: IncomingAttachment;
 21→  discussEntityId?: string;
 22→};
 23→
 24→const onboardingActions = new Set(["finalize_onboarding", "continue_onboarding"]);
 25→
 26→export function parseCreateWorkspaceRequest(body: unknown):
 27→  | { ok: true; data: CreateWorkspaceRequest }
 28→  | { ok: false; error: string } {
 29→  if (!body || typeof body !== "object") {
 30→    return { ok: false, error: "Body must be an object" };
 31→  }
 32→
 33→  const payload = body as Partial<CreateWorkspaceRequest>;
 34→
 35→  if (!payload.name || payload.name.trim().length === 0) {
 36→    return { ok: false, error: "name is required" };
 37→  }
 38→
 39→  const description = typeof payload.description === "string" ? payload.description.trim() : undefined;
 40→  const repoPath = typeof payload.repoPath === "string" ? payload.repoPath.trim() : undefined;
 41→
 42→  return {
 43→    ok: true,
 44→    data: {
 45→      name: payload.name.trim(),
 46→      ...(description && description.length > 0 ? { description } : {}),
 47→      ...(repoPath && repoPath.length > 0 ? { repoPath } : {}),
 48→    },
 49→  };
 50→}
 51→
 52→export async function parseIncomingMessageRequest(
 53→  request: Request,
 54→): Promise<{ ok: true; data: ParsedIncomingMessage } | { ok: false; error: string }> {
 55→  const contentType = request.headers.get("content-type") ?? "";
 56→
 57→  if (contentType.includes("multipart/form-data")) {
 58→    const formData = await request.formData();
 59→
 60→    const clientMessageIdValue = formData.get("clientMessageId");
 61→    const workspaceIdValue = formData.get("workspaceId");
 62→    const conversationIdValue = formData.get("conversationId");
 63→    const textValue = formData.get("text");
 64→    const onboardingActionValue = formData.get("onboardingAction");
 65→    const discussEntityIdValue = formData.get("discussEntityId");
 66→
 67→    if (typeof clientMessageIdValue !== "string" || clientMessageIdValue.trim().length === 0) {
 68→      return { ok: false, error: "clientMessageId is required" };
 69→    }
 70→
 71→    if (typeof workspaceIdValue !== "string" || workspaceIdValue.trim().length === 0) {
 72→      return { ok: false, error: "workspaceId is required" };
 73→    }
 74→
 75→    const text = typeof textValue === "string" ? textValue.trim() : "";
 76→
 77→    const fileValue = formData.get("file");
 78→    let attachment: IncomingAttachment | undefined;
 79→    if (fileValue instanceof File) {
 80→      try {
 81→        attachment = await parseIncomingAttachment(fileValue);
 82→      } catch (error) {
 83→        if (error instanceof HttpError) {
 84→          return { ok: false, error: error.message };
 85→        }
 86→        throw error;
 87→      }
 88→    }
 89→
 90→    if (!attachment && text.length === 0) {
 91→      return { ok: false, error: "text is required when no file is uploaded" };
 92→    }
 93→
 94→    const conversationId =
 95→      typeof conversationIdValue === "string" && conversationIdValue.trim().length > 0
 96→        ? conversationIdValue.trim()
 97→        : undefined;
 98→    const onboardingAction = typeof onboardingActionValue === "string" && onboardingActionValue.trim().length > 0
 99→      ? onboardingActionValue.trim()
100→      : undefined;
101→    if (onboardingAction && !onboardingActions.has(onboardingAction)) {
102→      return { ok: false, error: "onboardingAction must be finalize_onboarding or continue_onboarding" };
103→    }
104→
105→    const discussEntityId =
106→      typeof discussEntityIdValue === "string" && discussEntityIdValue.trim().length > 0
107→        ? discussEntityIdValue.trim()
108→        : undefined;
109→
110→    return {
111→      ok: true,
112→      data: {
113→        clientMessageId: clientMessageIdValue.trim(),
114→        workspaceId: workspaceIdValue.trim(),
115→        ...(conversationId ? { conversationId } : {}),
116→        text,
117→        ...(onboardingAction ? { onboardingAction: onboardingAction as OnboardingAction } : {}),
118→        ...(attachment ? { attachment } : {}),
119→        ...(discussEntityId ? { discussEntityId } : {}),
120→      },
121→    };
122→  }
123→
124→  let body: unknown;
125→  try {
126→    body = await request.json();
127→  } catch {
128→    return { ok: false, error: "Request body must be valid JSON" };
129→  }
130→
131→  if (!body || typeof body !== "object") {
132→    return { ok: false, error: "Body must be an object" };
133→  }
134→
135→  const payload = body as Partial<ParsedIncomingMessage>;
136→
137→  if (!payload.clientMessageId || payload.clientMessageId.trim().length === 0) {
138→    return { ok: false, error: "clientMessageId is required" };
139→  }
140→
141→  if (!payload.workspaceId || payload.workspaceId.trim().length === 0) {
142→    return { ok: false, error: "workspaceId is required" };
143→  }
144→
145→  if (!payload.text || payload.text.trim().length === 0) {
146→    return { ok: false, error: "text is required" };
147→  }
148→
149→  if (payload.conversationId && payload.conversationId.trim().length === 0) {
150→    return { ok: false, error: "conversationId must not be empty when provided" };
151→  }
152→
153→  if (payload.onboardingAction && !onboardingActions.has(payload.onboardingAction)) {
154→    return { ok: false, error: "onboardingAction must be finalize_onboarding or continue_onboarding" };
155→  }
156→
157→  const discussEntityId = (body as Record<string, unknown>).discussEntityId;
158→
159→  return {
160→    ok: true,
161→    data: {
162→      clientMessageId: payload.clientMessageId.trim(),
163→      workspaceId: payload.workspaceId.trim(),
164→      ...(payload.conversationId ? { conversationId: payload.conversationId.trim() } : {}),
165→      text: payload.text.trim(),
166→      ...(payload.onboardingAction ? { onboardingAction: payload.onboardingAction } : {}),
167→      ...(typeof discussEntityId === "string" && discussEntityId.trim().length > 0
168→        ? { discussEntityId: discussEntityId.trim() }
169→        : {}),
170→    },
171→  };
172→}
173→
174→async function parseIncomingAttachment(file: File): Promise<IncomingAttachment> {
175→  if (file.size > MAX_UPLOAD_BYTES) {
176→    throw new HttpError(400, `file is too large, max size is ${MAX_UPLOAD_BYTES} bytes`);
177→  }
178→
179→  const extension = file.name.split(".").pop()?.toLowerCase();
180→  if (!extension || !allowedUploadExtensions.has(extension)) {
181→    throw new HttpError(400, "only .md and .txt files are supported in phase 1");
182→  }
183→
184→  const content = (await file.text()).trim();
185→  if (content.length === 0) {
186→    throw new HttpError(400, "uploaded file content is empty");
187→  }
188→
189→  return {
190→    fileName: file.name,
191→    mimeType: file.type.trim().length > 0 ? file.type : "text/plain",
192→    sizeBytes: file.size,
193→    content,
194→  };
195→}
