  1→/**
  2→ * AgentStatusSection -- shows agent assignment and live status for tasks.
  3→ *
  4→ * Pure core: deriveAgentStatusView computes what to render from entity + session data.
  5→ * Effect boundary: the component wires useAgentSession for SSE updates and assignAgent for dispatch.
  6→ */
  7→
  8→import { useState } from "react";
  9→import type { AgentSessionSummary, EntityKind } from "../../../shared/contracts";
 10→import { useAgentSession, type AgentSessionStatus } from "../../hooks/use-agent-session";
 11→import { assignAgent, type AssignAgentResponse } from "../../graph/orchestrator-api";
 12→import { useWorkspaceState } from "../../stores/workspace-state";
 13→
 14→// ---------------------------------------------------------------------------
 15→// Pure core: view derivation
 16→// ---------------------------------------------------------------------------
 17→
 18→const ASSIGNABLE_STATUSES = new Set(["ready", "todo"]);
 19→
 20→export type AgentStatusViewHidden = { variant: "hidden" };
 21→export type AgentStatusViewAssign = { variant: "assign" };
 22→export type AgentStatusViewActive = {
 23→  variant: "active";
 24→  agentSessionId: string;
 25→  orchestratorStatus: string;
 26→  filesChangedCount: number;
 27→  streamUrl: string;
 28→  startedAt: string;
 29→};
 30→
 31→export type AgentStatusView =
 32→  | AgentStatusViewHidden
 33→  | AgentStatusViewAssign
 34→  | AgentStatusViewActive;
 35→
 36→export type DeriveAgentStatusInput = {
 37→  entityKind: string;
 38→  entityStatus: string;
 39→  agentSession?: AgentSessionSummary;
 40→};
 41→
 42→export function deriveAgentStatusView(input: DeriveAgentStatusInput): AgentStatusView {
 43→  if (input.entityKind !== "task") {
 44→    return { variant: "hidden" };
 45→  }
 46→
 47→  if (input.agentSession) {
 48→    return {
 49→      variant: "active",
 50→      agentSessionId: input.agentSession.agentSessionId,
 51→      orchestratorStatus: input.agentSession.orchestratorStatus,
 52→      filesChangedCount: input.agentSession.filesChangedCount,
 53→      streamUrl: `/api/orchestrator/stream/${encodeURIComponent(input.agentSession.streamId)}`,
 54→      startedAt: input.agentSession.startedAt,
 55→    };
 56→  }
 57→
 58→  if (ASSIGNABLE_STATUSES.has(input.entityStatus)) {
 59→    return { variant: "assign" };
 60→  }
 61→
 62→  return { variant: "hidden" };
 63→}
 64→
 65→// ---------------------------------------------------------------------------
 66→// Status badge display
 67→// ---------------------------------------------------------------------------
 68→
 69→const STATUS_LABELS: Record<AgentSessionStatus, string> = {
 70→  spawning: "Spawning",
 71→  active: "Working",
 72→  idle: "Idle",
 73→  completed: "Completed",
 74→  aborted: "Aborted",
 75→  error: "Error",
 76→};
 77→
 78→function statusLabel(status: AgentSessionStatus): string {
 79→  return STATUS_LABELS[status];
 80→}
 81→
 82→// ---------------------------------------------------------------------------
 83→// Component
 84→// ---------------------------------------------------------------------------
 85→
 86→export function AgentStatusSection({
 87→  entityId,
 88→  workspaceId,
 89→  entityKind,
 90→  entityStatus,
 91→  agentSession,
 92→}: {
 93→  entityId: string;
 94→  workspaceId: string;
 95→  entityKind: EntityKind;
 96→  entityStatus: string;
 97→  agentSession?: AgentSessionSummary;
 98→}) {
 99→  const repoPath = useWorkspaceState((s) => s.repoPath);
100→  const [assigning, setAssigning] = useState(false);
101→  const [assignError, setAssignError] = useState<string | undefined>();
102→  const [assignResult, setAssignResult] = useState<AssignAgentResponse | undefined>();
103→
104→  // Derive the initial view from props
105→  const initialView = deriveAgentStatusView({ entityKind, entityStatus, agentSession });
106→
107→  // If we have an assign result, use its stream URL; otherwise use session from props.
108→  // streamUrl is a dependency of useAgentSession's useEffect, so when assignResult
109→  // arrives and triggers a re-render, the hook will start the SSE subscription.
110→  const streamUrl = assignResult?.streamUrl ?? (initialView.variant === "active" ? initialView.streamUrl : undefined);
111→  const startedAt = initialView.variant === "active" ? initialView.startedAt : new Date().toISOString();
112→
113→  // SSE subscription -- only active when we have a stream URL
114→  const { state: sessionState } = useAgentSession(streamUrl, startedAt);
115→
116→  // Determine what to show
117→  const hasActiveStream = streamUrl !== undefined;
118→
119→  if (initialView.variant === "hidden" && !hasActiveStream) {
120→    return undefined;
121→  }
122→
123→  async function handleAssign() {
124→    if (assigning) return;
125→    setAssigning(true);
126→    setAssignError(undefined);
127→    try {
128→      const result = await assignAgent(workspaceId, entityId);
129→      setAssignResult(result);
130→    } catch (err) {
131→      setAssignError(err instanceof Error ? err.message : "Failed to assign agent");
132→    } finally {
133→      setAssigning(false);
134→    }
135→  }
136→
137→  // Show active session view (either from props or from fresh assignment)
138→  if (hasActiveStream) {
139→    const displayStatus = sessionState.status;
140→    const displayFiles = initialView.variant === "active"
141→      ? initialView.filesChangedCount + sessionState.filesChanged
142→      : sessionState.filesChanged;
143→
144→    return (
145→      <div className="entity-detail-section agent-status-section">
146→        <h4>Agent</h4>
147→        <div className="agent-status-row">
148→          <span className={`agent-status-badge agent-status-${displayStatus}`} data-testid="agent-status-badge">
149→            {statusLabel(displayStatus)}
150→          </span>

